content.text:
'use client';

import Link from 'next/link';
import { useParams } from 'next/navigation';

// ─── Mock Quest Data ──────────────────────────────────────────────────────────

interface QuestObjective {
  description: string;
  progress: string;
  completed: boolean;
}

interface QuestReward {
  type: 'experience' | 'gold' | 'item' | 'title';
  name: string;
  value: string;
}

interface WalkthroughStep {
  step: number;
  title: string;
  description: string;
  tips: string[];
}

interface QuestEntry {
  id: string;
  name: string;
  npc: string;
  npcLocation: string;
  type: 'Main' | 'Side' | 'Daily' | 'Event' | 'Dungeon';
  difficulty: 'Easy' | 'Normal' | 'Hard' | 'Nightmare';
  levelRequirement: number;
  description: string;
  objectives: QuestObjective[];
  rewards: QuestReward[];
  walkthrough: WalkthroughStep[];
  prerequisites: string[];
  followUpQuests: string[];
  relatedEntries: { id: string; title: string; category: string; href: string }[];
}

const mockQuests: Record<string, QuestEntry> = {
  'quest-1': {
    id: 'quest-1',
    name: "The Dragon's Bane",
    npc: 'Elder Theron',
    npcLocation: 'Starfall Village',
    type: 'Main',
    difficulty: 'Nightmare',
    levelRequirement: 85,
    description: 'The ancient Shadow Dragon has awakened in the Abyssal Caverns, corrupting the land with dark magic. Elder Theron has tasked you with venturing into the depths and defeating this legendary beast. Success will grant you access to legendary equipment and eternal glory.',
    objectives: [
      { description: 'Reach the Abyssal Caverns Floor B5', progress: 'Navigate through 4 floors of the dungeon', completed: false },
      { description: 'Defeat the Shadow Dragon', progress: 'Boss battle - requires party or high gear', completed: false },
      { description: 'Return to Elder Theron', progress: 'Report your victory', completed: false },
    ],
    rewards: [
      { type: 'experience', name: 'Experience', value: '2,500,000 EXP' },
      { type: 'gold', name: 'Gold', value: '1,000,000 Gold' },
      { type: 'item', name: 'Legendary Weapon Selection Box', value: 'Choose 1 of 3 legendary weapons' },
      { type: 'title', name: 'Title', value: '"Dragon Slayer"' },
    ],
    walkthrough: [
      {
        step: 1,
        title: 'Preparation',
        description: 'Stock up on potions and buffs. Bring at least 50 Health Potions XL and 20 Mana Potions. Equip your best gear and consider bringing a party.',
        tips: [
          'Bring fire and holy magic users for maximum damage',
          'Shadow Dragon is weak to light and holy attacks',
          'Bring protection scrolls to prevent equipment downgrade',
        ],
      },
      {
        step: 2,
        title: 'Navigate to Floor B5',
        description: 'Enter the Abyssal Caverns and work your way down through 4 floors. Each floor has progressively stronger monsters. Use the map coordinates to find the fastest route.',
        tips: [
          'Floor B1-B2: Shadow Wraiths (Lv.75)',
          'Floor B3-B4: Dark Knights (Lv.80)',
          'Avoid unnecessary fights to conserve resources',
        ],
      },
      {
        step: 3,
        title: 'Shadow Dragon Boss Fight',
        description: 'The Shadow Dragon has multiple phases. In phase 1, focus on dealing damage. In phase 2, it will summon shadow clones - destroy them quickly. In phase 3, use holy magic to break its dark shield.',
        tips: [
          'Phase 1: 2,500,000 HP - standard attacks work',
          'Phase 2: Destroy 3 shadow clones before they heal the boss',
          'Phase 3: Use holy magic to break the dark shield, then burst damage',
          'Watch for Shadow Breath attack - dodge or use invulnerability potion',
        ],
      },
      {
        step: 4,
        title: 'Return to Elder Theron',
        description: 'After defeating the Shadow Dragon, return to Elder Theron in Starfall Village to complete the quest and claim your rewards.',
        tips: [
          'Use a Teleport Scroll to quickly return to town',
          'Talk to Elder Theron to complete the quest',
        ],
      },
    ],
    prerequisites: ['Guild Initiation (Lv.30+)', 'Level 85+'],
    followUpQuests: ['The Frozen Throne', 'Lost Artifacts'],
    relatedEntries: [
      { id: 'mon-1', title: 'Shadow Dragon', category: 'monsters', href: '/wiki/monsters/mon-1' },
      { id: 'map-1', title: 'Abyssal Caverns', category: 'maps', href: '/wiki?category=maps' },
      { id: 'npc-1', title: 'Elder Theron', category: 'npcs', href: '/wiki?category=npcs' },
      { id: 'item-1', title: 'Elixir of Immortality', category: 'items', href: '/wiki/items/item-1' },
    ],
  },
  'quest-2': {
    id: 'quest-2',
    name: 'Lost Artifacts',
    npc: 'Archaeologist Petra',
    npcLocation: 'Iron City - Museum',
    type: 'Main',
    difficulty: 'Hard',
    levelRequirement: 70,
    description: 'An ancient civilization left behind 5 powerful artifacts scattered across the world. Archaeologist Petra believes these artifacts hold the key to unlocking a secret dungeon. Collect all 5 artifacts to prove your worth.',
    objectives: [
      { description: 'Collect Artifact of Fire', progress: 'Located in Volcanic Ridge', completed: false },
      { description: 'Collect Artifact of Ice', progress: 'Located in Frozen Peaks', completed: false },
      { description: 'Collect Artifact of Earth', progress: 'Located in Ruins of Eldara', completed: false },
      { description: 'Collect Artifact of Wind', progress: 'Located in Sky Tower', completed: false },
      { description: 'Collect Artifact of Light', progress: 'Located in Holy Temple', completed: false },
      { description: 'Return to Archaeologist Petra', progress: 'Complete the quest', completed: false },
    ],
    rewards: [
      { type: 'experience', name: 'Experience', value: '1,800,000 EXP' },
      { type: 'gold', name: 'Gold', value: '500,000 Gold' },
      { type: 'item', name: 'Secret Dungeon Key', value: 'Access to Secret Dungeon' },
      { type: 'title', name: 'Title', value: '"Artifact Collector"' },
    ],
    walkthrough: [
      {
        step: 1,
        title: 'Artifact of Fire',
        description: 'Travel to Volcanic Ridge and defeat the Fire Elemental boss guarding the artifact. The artifact is located at coordinates (450, 320).',
        tips: [
          'Fire Elemental is weak to water and ice magic',
          'Bring cold resistance potions',
          'The artifact is in a treasure chest after defeating the boss',
        ],
      },
      {
        step: 2,
        title: 'Artifact of Ice',
        description: 'Head to Frozen Peaks and locate the artifact in the Ice Cave. You\'ll need to solve a puzzle involving ice blocks.',
        tips: [
          'The puzzle requires moving ice blocks to create a path',
          'Bring fire magic to melt certain ice walls',
          'Coordinates: (180, 290)',
        ],
      },
      {
        step: 3,
        title: 'Artifact of Earth',
        description: 'Visit the Ruins of Eldara and defeat the Ancient Golem guarding the artifact. This is a tough fight - bring your best gear.',
        tips: [
          'Ancient Golem has extremely high defense',
          'Use magic attacks to bypass its stone armor',
          'The artifact is in the treasure chamber after victory',
        ],
      },
      {
        step: 4,
        title: 'Artifact of Wind',
        description: 'Climb Sky Tower and reach the top floor. The artifact is guarded by wind elementals. Navigate the tower carefully.',
        tips: [
          'Sky Tower has 20 floors',
          'Each floor has progressively stronger wind elementals',
          'Use earth magic for advantage',
        ],
      },
      {
        step: 5,
        title: 'Artifact of Light',
        description: 'Enter the Holy Temple and complete the holy trials. The artifact is in the inner sanctum.',
        tips: [
          'The temple requires you to solve riddles',
          'Dark magic users may face penalties',
          'Bring holy water for the final chamber',
        ],
      },
    ],
    prerequisites: ['Level 70+'],
    followUpQuests: ['The Dragon\'s Bane'],
    relatedEntries: [
      { id: 'mon-4', title: 'Ancient Golem', category: 'monsters', href: '/wiki/monsters/mon-4' },
      { id: 'map-1', title: 'Abyssal Caverns', category: 'maps', href: '/wiki?category=maps' },
    ],
  },
  'quest-3': {
    id: 'quest-3',
    name: 'Guild Initiation',
    npc: 'Captain Rex',
    npcLocation: 'Iron City - Guild Hall',
    type: 'Main',
    difficulty: 'Normal',
    levelRequirement: 30,
    description: 'To join or create a guild, you must first prove yourself worthy by completing the Guild Initiation quest. Captain Rex will assign you 3 tasks to test your combat skills and dedication.',
    objectives: [
      { description: 'Defeat 20 Goblin Warriors', progress: 'Hunt in Goblin Forest', completed: false },
      { description: 'Collect 10 Goblin Ears', progress: 'Drop from Goblin Shaman', completed: false },
      { description: 'Defeat the Goblin Shaman Boss', progress: 'Final boss battle', completed: false },
    ],
    rewards: [
      { type: 'experience', name: 'Experience', value: '150,000 EXP' },
      { type: 'gold', name: 'Gold', value: '50,000 Gold' },
      { type: 'item', name: 'Guild Initiate Badge', value: 'Required for guild creation' },
      { type: 'title', name: 'Title', value: '"Guild Initiate"' },
    ],
    walkthrough: [
      {
        step: 1,
        title: 'Hunt Goblin Warriors',
        description: 'Travel to Goblin Forest and defeat 20 Goblin Warriors. They are level 30-35 enemies.',
        tips: [
          'Goblin Warriors spawn in groups of 2-3',
          'They are weak to fire magic',
          'Coordinates: (150, 220)',
        ],
      },
      {
        step: 2,
        title: 'Collect Goblin Ears',
        description: 'Defeat Goblin Shamans to collect 10 Goblin Ears. These are used as proof of your hunting prowess.',
        tips: [
          'Goblin Shamans have an 80% drop rate for Goblin Ears',
          'They are stronger than regular warriors',
          'You need to defeat approximately 13 shamans to get 10 ears',
        ],
      },
      {
        step: 3,
        title: 'Defeat Goblin Shaman Boss',
        description: 'Locate and defeat the Goblin Shaman Boss in the Shaman Hut. This is the final test of your combat ability.',
        tips: [
          'The boss has healing abilities - interrupt them when possible',
          'It summons minions - clear them quickly',
          'Use fire magic for maximum damage',
        ],
      },
    ],
    prerequisites: ['Level 30+'],
    followUpQuests: ['The Dragon\'s Bane', 'Lost Artifacts'],
    relatedEntries: [
      { id: 'mon-3', title: 'Goblin Shaman', category: 'monsters', href: '/wiki/monsters/mon-3' },
      { id: 'npc-4', title: 'Captain Rex', category: 'npcs', href: '/wiki?category=npcs' },
    ],
  },
  'quest-4': {
    id: 'quest-4',
    name: 'The Frozen Throne',
    npc: 'Frost Sage Elara',
    npcLocation: 'Frozen Peaks - Ice Tower',
    type: 'Main',
    difficulty: 'Hard',
    levelRequirement: 75,
    description: 'An ancient disturbance has awakened the Ice King in the Frozen Peaks. Frost Sage Elara fears his awakening signals the return of an ancient evil. Investigate the disturbance and defeat the Ice King to restore peace.',
    objectives: [
      { description: 'Investigate the Frozen Peaks', progress: 'Explore and gather clues', completed: false },
      { description: 'Defeat the Frost Giants', progress: 'Clear the path to the Ice King', completed: false },
      { description: 'Defeat the Ice King', progress: 'Final boss battle', completed: false },
      { description: 'Return to Frost Sage Elara', progress: 'Report your findings', completed: false },
    ],
    rewards: [
      { type: 'experience', name: 'Experience', value: '1,500,000 EXP' },
      { type: 'gold', name: 'Gold', value: '400,000 Gold' },
      { type: 'item', name: 'Frost Armor Set', value: 'Epic ice-themed armor' },
      { type: 'title', name: 'Title', value: '"Frost Conqueror"' },
    ],
    walkthrough: [
      {
        step: 1,
        title: 'Investigate the Frozen Peaks',
        description: 'Explore the Frozen Peaks and gather clues about the disturbance. Talk to NPCs and examine suspicious locations.',
        tips: [
          'Visit the Ice Tower entrance',
          'Talk to the Frost Sage for hints',
          'Examine the frozen statues for clues',
        ],
      },
      {
        step: 2,
        title: 'Defeat Frost Giants',
        description: 'Clear the path to the Ice King by defeating 3 Frost Giants guarding the tower.',
        tips: [
          'Frost Giants are weak to fire magic',
          'They have high defense - use magic attacks',
          'Each giant drops valuable frost materials',
        ],
      },
      {
        step: 3,
        title: 'Defeat the Ice King',
        description: 'Reach the top of the Ice Tower and defeat the Ice King in an epic battle.',
        tips: [
          'The Ice King has 1,500,000 HP',
          'Use fire magic for maximum damage',
          'Watch for the Blizzard attack - dodge or use protection',
          'The fight has 2 phases',
        ],
      },
    ],
    prerequisites: ['Level 75+'],
    followUpQuests: [],
    relatedEntries: [
      { id: 'mon-2', title: 'Frost Giant', category: 'monsters', href: '/wiki/monsters/mon-2' },
      { id: 'map-2', title: 'Frozen Peaks', category: 'maps', href: '/wiki?category=maps' },
    ],
  },
};

const difficultyColors: Record<string, string> = {
  Easy: 'bg-green-500/20 text-green-400 border-green-500/30',
  Normal: 'bg-blue-500/20 text-blue-400 border-blue-500/30',
  Hard: 'bg-orange-500/20 text-orange-400 border-orange-500/30',
  Nightmare: 'bg-red-500/20 text-red-400 border-red-500/30',
};

const typeColors: Record<string, string> = {
  Main: 'bg-purple-500/20 text-purple-400 border-purple-500/30',
  Side: 'bg-cyan-500/20 text-cyan-400 border-cyan-500/30',
  Daily: 'bg-yellow-500/20 text-yellow-400 border-yellow-500/30',
  Event: 'bg-pink-500/20 text-pink-400 border-pink-500/30',
  Dungeon: 'bg-red-500/20 text-red-400 border-red-500/30',
};

const rewardTypeIcons: Record<string, string> = {
  experience: '⭐',
  gold: '💰',
  item: '🎁',
  title: '🏆',
};

export default function QuestEntryPage() {
  const params = useParams();
  const questId = params.id as string;
  const quest = mockQuests[questId];

  if (!quest) {
    return (
      <div className="space-y-4">
        <nav className="flex items-center gap-2 text-sm text-muted-foreground">
          <Link href="/wiki" className="hover:text-white transition-colors">Wiki</Link>
          <span>/</span>
          <Link href="/wiki?category=quests" className="hover:text-white transition-colors">Quests</Link>
          <span>/</span>
          <span className="text-white">Not Found</span>
        </nav>
        <div className="rounded-2xl border-2 border-white/10 backdrop-blur-[16px] bg-[rgba(17,17,17,0.7)] p-12 text-center">
          <div className="text-4xl mb-3">📜</div>
          <h2 className="font-heading text-xl font-bold text-white">Quest Not Found</h2>
          <p className="mt-2 text-muted-foreground">The quest you&apos;re looking for doesn&apos;t exist in our database.</p>
          <Link href="/wiki?category=quests" className="mt-4 inline-block rounded-xl border-2 border-primary bg-primary/20 px-6 py-2 text-sm font-medium text-white hover:bg-primary/30 transition-colors">
            Browse Quests
          </Link>
        </div>
      </div>
    );
  }

  return (
    <div className="space-y-6">
      {/* Breadcrumb Navigation */}
      <nav className="flex items-center gap-2 text-sm text-muted-foreground" aria-label="Breadcrumb">
        <Link href="/wiki" className="hover:text-white transition-colors">Wiki</Link>
        <span className="text-white/30">/</span>
        <Link href="/wiki?category=quests" className="hover:text-white transition-colors">Quests</Link>
        <span className="text-white/30">/</span>
        <span className="text-white font-medium">{quest.name}</span>
      </nav>

      {/* Quest Header */}
      <div className="rounded-2xl border-2 border-white/10 backdrop-blur-[16px] bg-[rgba(17,17,17,0.7)] p-6">
        <div className="space-y-4">
          <div className="flex flex-wrap items-center gap-3">
            <h1 className="font-heading text-2xl sm:text-3xl font-bold text-white">{quest.name}</h1>
            <span className={`inline-flex items-center rounded-full border px-3 py-1 text-xs font-medium ${typeColors[quest.type]}`}>
              {quest.type}
            </span>
            <span className={`inline-flex items-center rounded-full border px-3 py-1 text-xs font-medium ${difficultyColors[quest.difficulty]}`}>
              {quest.difficulty}
            </span>
          </div>
          <p className="text-muted-foreground leading-relaxed">{quest.description}</p>

          {/* Quest Info Grid */}
          <div className="grid grid-cols-2 sm:grid-cols-4 gap-3">
            <div className="rounded-xl border border-white/10 bg-[rgba(6,6,6,0.5)] p-3 text-center">
              <div className="text-xs text-muted-foreground">NPC</div>
              <div className="font-heading text-sm font-bold text-white">{quest.npc}</div>
            </div>
            <div className="rounded-xl border border-white/10 bg-[rgba(6,6,6,0.5)] p-3 text-center">
              <div className="text-xs text-muted-foreground">Location</div>
              <div className="font-heading text-sm font-bold text-white">{quest.npcLocation}</div>
            </div>
            <div className="rounded-xl border border-white/10 bg-[rgba(6,6,6,0.5)] p-3 text-center">
              <div className="text-xs text-muted-foreground">Level Req.</div>
              <div className="font-heading text-lg font-bold text-cyan-400">{quest.levelRequirement}+</div>
            </div>
            <div className="rounded-xl border border-white/10 bg-[rgba(6,6,6,0.5)] p-3 text-center">
              <div className="text-xs text-muted-foreground">Objectives</div>
              <div className="font-heading text-lg font-bold text-yellow-400">{quest.objectives.length}</div>
            </div>
          </div>
        </div>
      </div>

      {/* Objectives */}
      <div className="rounded-2xl border-2 border-white/10 backdrop-blur-[16px] bg-[rgba(17,17,17,0.7)] p-5">
        <h2 className="font-heading text-lg font-semibold text-white mb-4">Objectives</h2>
        <div className="space-y-3">
          {quest.objectives.map((obj, idx) => (
            <div key={idx} className="flex gap-3 rounded-xl border border-white/10 bg-[rgba(6,6,6,0.5)] p-4">
              <div className="shrink-0 flex items-center justify-center w-6 h-6 rounded-full border-2 border-primary/50 bg-primary/10 text-xs font-bold text-primary">
                {idx + 1}
              </div>
              <div className="flex-1">
                <div className="text-sm font-medium text-white">{obj.description}</div>
                <div className="text-xs text-muted-foreground mt-1">{obj.progress}</div>
              </div>
            </div>
          ))}
        </div>
      </div>

      {/* Rewards */}
      <div className="rounded-2xl border-2 border-white/10 backdrop-blur-[16px] bg-[rgba(17,17,17,0.7)] p-5">
        <h2 className="font-heading text-lg font-semibold text-white mb-4">Rewards</h2>
        <div className="grid grid-cols-1 sm:grid-cols-2 gap-3">
          {quest.rewards.map((reward, idx) => (
            <div key={idx} className="flex items-center gap-3 rounded-xl border border-white/10 bg-[rgba(6,6,6,0.5)] p-4">
              <span className="text-2xl">{rewardTypeIcons[reward.type]}</span>
              <div>
                <div className="text-sm font-medium text-white">{reward.name}</div>
                <div className="text-xs text-muted-foreground">{reward.value}</div>
              </div>
            </div>
          ))}
        </div>
      </div>

      {/* Prerequisites */}
      {quest.prerequisites.length > 0 && (
        <div className="rounded-2xl border-2 border-white/10 backdrop-blur-[16px] bg-[rgba(17,17,17,0.7)] p-5">
          <h2 className="font-heading text-lg font-semibold text-white mb-4">Prerequisites</h2>
          <div className="flex flex-wrap gap-2">
            {quest.prerequisites.map((prereq, idx) => (
              <span key={idx} className="inline-flex items-center rounded-lg border border-yellow-500/30 bg-yellow-500/10 px-3 py-1.5 text-sm font-medium text-yellow-400">
                {prereq}
              </span>
            ))}
          </div>
        </div>
      )}

      {/* Walkthrough */}
      <div className="rounded-2xl border-2 border-white/10 backdrop-blur-[16px] bg-[rgba(17,17,17,0.7)] p-5">
        <h2 className="font-heading text-lg font-semibold text-white mb-4">Walkthrough</h2>
        <div className="space-y-4">
          {quest.walkthrough.map((step) => (
            <div key={step.step} className="rounded-xl border border-white/10 bg-[rgba(6,6,6,0.5)] p-4">
              <div className="flex items-start gap-3 mb-3">
                <div className="shrink-0 flex items-center justify-center w-8 h-8 rounded-full bg-primary/20 border border-primary/50 text-sm font-bold text-primary">
                  {step.step}
                </div>
                <div>
                  <h3 className="font-heading text-sm font-semibold text-white">{step.title}</h3>
                </div>
              </div>
              <p className="text-sm text-muted-foreground mb-3">{step.description}</p>
              {step.tips.length > 0 && (
                <div className="space-y-1">
                  <h4 className="text-xs font-medium text-cyan-400 mb-2">💡 Tips:</h4>
                  <ul className="space-y-1">
                    {step.tips.map((tip, idx) => (
                      <li key={idx} className="text-xs text-muted-foreground flex gap-2">
                        <span className="shrink-0">•</span>
                        <span>{tip}</span>
                      </li>
                    ))}
                  </ul>
                </div>
              )}
            </div>
          ))}
        </div>
      </div>

      {/* Follow-up Quests */}
      {quest.followUpQuests.length > 0 && (
        <div className="rounded-2xl border-2 border-white/10 backdrop-blur-[16px] bg-[rgba(17,17,17,0.7)] p-5">
          <h2 className="font-heading text-lg font-semibold text-white mb-4">Follow-up Quests</h2>
          <div className="space-y-2">
            {quest.followUpQuests.map((followUp, idx) => (
              <Link
                key={idx}
                href="/wiki?category=quests"
                className="flex items-center gap-2 rounded-lg border border-white/10 bg-[rgba(6,6,6,0.5)] p-3 hover:border-primary/30 hover:bg-primary/5 transition-all duration-200"
              >
                <span className="text-lg">📜</span>
                <span className="text-sm font-medium text-white">{followUp}</span>
              </Link>
            ))}
          </div>
        </div>
      )}

      {/* Related Entries */}
      <div className="rounded-2xl border-2 border-white/10 backdrop-blur-[16px] bg-[rgba(17,17,17,0.7)] p-5">
        <h2 className="font-heading text-lg font-semibold text-white mb-4">Related Entries</h2>
        <div className="grid grid-cols-1 sm:grid-cols-2 gap-3">
          {quest.relatedEntries.map((entry) => (
            <Link
              key={entry.id}
              href={entry.href}
              className="flex items-center gap-3 rounded-xl border border-white/10 bg-[rgba(6,6,6,0.5)] p-4 hover:border-primary/30 hover:bg-primary/5 transition-all duration-200"
            >
              <span className="text-lg">
                {entry.category === 'monsters' && '👹'}
                {entry.category === 'items' && '🧪'}
                {entry.category === 'maps' && '🗺️'}
                {entry.category === 'npcs' && '🧙'}
                {entry.category === 'quests' && '📜'}
                {entry.category === 'skills' && '✨'}
                {entry.category === 'equipment' && '⚔️'}
              </span>
              <div>
                <div className="text-sm font-medium text-white">{entry.title}</div>
                <div className="text-xs text-muted-foreground capitalize">{entry.category}</div>
              </div>
            </Link>
          ))}
        </div>
      </div>
    </div>
  );
}

'use client';

import Link from 'next/link';

interface SkillCard {
  id: string;
  name: string;
  class: string;
  type: 'Active' | 'Passive' | 'Ultimate';
  element: string;
  description: string;
}

const mockSkills: SkillCard[] = [
  {
    id: 'skill-1',
    name: 'Shadow Strike',
    class: 'Assassin',
    type: 'Active',
    element: 'Dark',
    description: 'Teleports behind the target and delivers a devastating strike with guaranteed critical hit.',
  },
  {
    id: 'skill-2',
    name: 'Holy Light',
    class: 'Priest',
    type: 'Active',
    element: 'Light',
    description: 'A powerful healing spell that restores HP to all party members within range.',
  },
  {
    id: 'skill-3',
    name: 'Meteor Storm',
    class: 'Mage',
    type: 'Ultimate',
    element: 'Fire',
