export default function MapEntryPage() {
  const params = useParams();
  const mapId = params.id as string;
  const map = mockMaps[mapId];

  if (!map) {
    return (
      <div className="space-y-4">
        <nav className="flex items-center gap-2 text-sm text-muted-foreground">
          <Link href="/wiki" className="hover:text-white transition-colors">Wiki</Link>
          <span>/</span>
          <Link href="/wiki?category=maps" className="hover:text-white transition-colors">Maps</Link>
          <span>/</span>
          <span className="text-white">Not Found</span>
        </nav>
        <div className="rounded-2xl border-2 border-white/10 backdrop-blur-[16px] bg-[rgba(17,17,17,0.7)] p-12 text-center">
          <div className="text-4xl mb-3">🗺️</div>
          <h2 className="font-heading text-xl font-bold text-white">Map Not Found</h2>
          <p className="mt-2 text-muted-foreground">The map you&apos;re looking for doesn&apos;t exist in our database.</p>
          <Link href="/wiki?category=maps" className="mt-4 inline-block rounded-xl border-2 border-primary bg-primary/20 px-6 py-2 text-sm font-medium text-white hover:bg-primary/30 transition-colors">
            Browse Maps
          </Link>
        </div>
      </div>
    );
  }

  return (
    <div className="space-y-6">
      {/* Breadcrumb Navigation */}
      <nav className="flex items-center gap-2 text-sm text-muted-foreground" aria-label="Breadcrumb">
        <Link href="/wiki" className="hover:text-white transition-colors">Wiki</Link>
        <span className="text-white/30">/</span>
        <Link href="/wiki?category=maps" className="hover:text-white transition-colors">Maps</Link>
        <span className="text-white/30">/</span>
        <span className="text-white font-medium">{map.name}</span>
      </nav>

      {/* Map Header */}
      <div className="rounded-2xl border-2 border-white/10 backdrop-blur-[16px] bg-[rgba(17,17,17,0.7)] p-6">
        <div className="space-y-4">
          <div className="flex flex-wrap items-center gap-3">
            <h1 className="font-heading text-2xl sm:text-3xl font-bold text-white">{map.name}</h1>
            <span className={`inline-flex items-center rounded-full border px-3 py-1 text-xs font-medium ${typeColors[map.type]}`}>
              {map.type}
            </span>
            {map.pvpEnabled && (
              <span className="inline-flex items-center rounded-full border border-red-500/30 bg-red-500/10 px-3 py-1 text-xs font-medium text-red-400">
                ⚔️ PvP Enabled
              </span>
            )}
          </div>
          <p className="text-muted-foreground leading-relaxed">{map.description}</p>

          {/* Quick Info */}
          <div className="grid grid-cols-2 sm:grid-cols-4 gap-3">
            <div className="rounded-xl border border-white/10 bg-[rgba(6,6,6,0.5)] p-3 text-center">
              <div className="text-xs text-muted-foreground">Level Range</div>
              <div className="font-heading text-lg font-bold text-cyan-400">{map.levelRange}</div>
            </div>
            <div className="rounded-xl border border-white/10 bg-[rgba(6,6,6,0.5)] p-3 text-center">
              <div className="text-xs text-muted-foreground">Size</div>
              <div className="font-heading text-sm font-bold text-white">{map.size}</div>
            </div>
            <div className="rounded-xl border border-white/10 bg-[rgba(6,6,6,0.5)] p-3 text-center">
              <div className="text-xs text-muted-foreground">Monsters</div>
              <div className="font-heading text-lg font-bold text-orange-400">{map.monsters.length}</div>
            </div>
            <div className="rounded-xl border border-white/10 bg-[rgba(6,6,6,0.5)] p-3 text-center">
              <div className="text-xs text-muted-foreground">NPCs</div>
              <div className="font-heading text-lg font-bold text-green-400">{map.npcs.length}</div>
            </div>
          </div>
        </div>
      </div>

      {/* Monsters */}
      {map.monsters.length > 0 && (
        <div className="rounded-2xl border-2 border-white/10 backdrop-blur-[16px] bg-[rgba(17,17,17,0.7)] p-5">
          <h2 className="font-heading text-lg font-semibold text-white mb-4">Monsters</h2>
          <div className="overflow-x-auto">
            <table className="w-full text-sm">
              <thead>
                <tr className="border-b border-white/10">
                  <th className="text-left py-3 px-4 text-muted-foreground font-medium">Name</th>
                  <th className="text-left py-3 px-4 text-muted-foreground font-medium">Level</th>
                  <th className="text-left py-3 px-4 text-muted-foreground font-medium">Type</th>
                  <th className="text-left py-3 px-4 text-muted-foreground font-medium">Spawn Rate</th>
                </tr>
              </thead>
              <tbody>
                {map.monsters.map((monster, idx) => (
                  <tr key={idx} className="border-b border-white/5 hover:bg-white/5 transition-colors">
                    <td className="py-3 px-4 text-white font-medium">{monster.name}</td>
                    <td className="py-3 px-4 text-cyan-400">{monster.level}</td>
                    <td className="py-3 px-4">
                      <span className={`inline-flex items-center rounded-full border px-2 py-0.5 text-xs font-medium ${
                        monster.type === 'Boss' ? 'border-red-500/30 bg-red-500/10 text-red-400' :
                        monster.type === 'Elite' ? 'border-orange-500/30 bg-orange-500/10 text-orange-400' :
                        'border-gray-500/30 bg-gray-500/10 text-gray-400'
                      }`}>
                        {monster.type}
                      </span>
                    </td>
                    <td className="py-3 px-4 text-muted-foreground">{monster.spawnRate}</td>
                  </tr>
                ))}
              </tbody>
            </table>
          </div>
        </div>
      )}

      {/* NPCs */}
      {map.npcs.length > 0 && (
        <div className="rounded-2xl border-2 border-white/10 backdrop-blur-[16px] bg-[rgba(17,17,17,0.7)] p-5">
          <h2 className="font-heading text-lg font-semibold text-white mb-4">NPCs</h2>
          <div className="grid grid-cols-1 sm:grid-cols-2 gap-3">
            {map.npcs.map((npc, idx) => (
              <div key={idx} className="rounded-xl border border-white/10 bg-[rgba(6,6,6,0.5)] p-4">
                <div className="text-sm font-medium text-white">{npc.name}</div>
                <div className="text-xs text-muted-foreground mt-1">{npc.role}</div>
                <div className="text-xs text-cyan-400 mt-1">📍 {npc.location}</div>
              </div>
            ))}
          </div>
        </div>
      )}

      {/* Dungeons */}
      {map.dungeons.length > 0 && (
        <div className="rounded-2xl border-2 border-white/10 backdrop-blur-[16px] bg-[rgba(17,17,17,0.7)] p-5">
          <h2 className="font-heading text-lg font-semibold text-white mb-4">Dungeons</h2>
          <div className="space-y-3">
            {map.dungeons.map((dungeon, idx) => (
              <div key={idx} className="rounded-xl border border-white/10 bg-[rgba(6,6,6,0.5)] p-4">
                <div className="flex flex-col sm:flex-row sm:items-center sm:justify-between gap-2 mb-3">
                  <div>
                    <div className="text-sm font-medium text-white">{dungeon.name}</div>
                    <div className="text-xs text-muted-foreground mt-1">Level Range: {dungeon.levelRange}</div>
                  </div>
                </div>
                <div className="space-y-2">
                  <div>
                    <h4 className="text-xs font-medium text-purple-400 mb-1">Bosses:</h4>
                    <div className="flex flex-wrap gap-2">
                      {dungeon.bosses.map((boss, bidx) => (
                        <span key={bidx} className="inline-flex items-center rounded-lg border border-red-500/30 bg-red-500/10 px-2 py-1 text-xs font-medium text-red-400">
                          {boss}
                        </span>
                      ))}
                    </div>
                  </div>
                  <div>
                    <h4 className="text-xs font-medium text-yellow-400 mb-1">Rewards:</h4>
                    <p className="text-xs text-muted-foreground">{dungeon.rewards}</p>
                  </div>
                </div>
              </div>
            ))}
          </div>
        </div>
      )}

      {/* Resources */}
      {map.resources.length > 0 && (
        <div className="rounded-2xl border-2 border-white/10 backdrop-blur-[16px] bg-[rgba(17,17,17,0.7)] p-5">
          <h2 className="font-heading text-lg font-semibold text-white mb-4">Harvestable Resources</h2>
          <div className="flex flex-wrap gap-2">
            {map.resources.map((resource, idx) => (
              <span key={idx} className="inline-flex items-center rounded-lg border border-green-500/30 bg-green-500/10 px-3 py-1.5 text-sm font-medium text-green-400">
                {resource}
              </span>
            ))}
          </div>
        </div>
      )}

      {/* Quests Available */}
      {map.questsAvailable.length > 0 && (
        <div className="rounded-2xl border-2 border-white/10 backdrop-blur-[16px] bg-[rgba(17,17,17,0.7)] p-5">
          <h2 className="font-heading text-lg font-semibold text-white mb-4">Quests Available</h2>
          <div className="space-y-2">
            {map.questsAvailable.map((quest, idx) => (
              <Link
                key={idx}
                href="/wiki?category=quests"
                className="flex items-center gap-2 rounded-lg border border-white/10 bg-[rgba(6,6,6,0.5)] p-3 hover:border-primary/30 hover:bg-primary/5 transition-all duration-200"
              >
                <span className="text-lg">📜</span>
                <span className="text-sm font-medium text-white">{quest}</span>
              </Link>
            ))}
          </div>
        </div>
      )}

      {/* Travel Methods */}
      <div className="rounded-2xl border-2 border-white/10 backdrop-blur-[16px] bg-[rgba(17,17,17,0.7)] p-5">
        <h2 className="font-heading text-lg font-semibold text-white mb-4">How to Get There</h2>
        <div className="space-y-2">
          {map.travelMethods.map((method, idx) => (
            <div key={idx} className="flex items-center gap-3 rounded-lg border border-white/10 bg-[rgba(6,6,6,0.5)] p-3">
              <span className="text-cyan-400">→</span>
              <span className="text-sm text-muted-foreground">{method}</span>
            </div>
          ))}
        </div>
      </div>

      {/* Related Entries */}
      <div className="rounded-2xl border-2 border-white/10 backdrop-blur-[16px] bg-[rgba(17,17,17,0.7)] p-5">
        <h2 className="font-heading text-lg font-semibold text-white mb-4">Related Entries</h2>
        <div className="grid grid-cols-1 sm:grid-cols-2 gap-3">
          {map.relatedEntries.map((entry) => (
            <Link
              key={entry.id}
              href={entry.href}
              className="flex items-center gap-3 rounded-xl border border-white/10 bg-[rgba(6,6,6,0.5)] p-4 hover:border-primary/30 hover:bg-primary/5 transition-all duration-200"
            >
              <span className="text-lg">
                {entry.category === 'monsters' && '👹'}
                {entry.category === 'items' && '🧪'}
                {entry.category === 'equipment' && '⚔️'}
                {entry.category === 'npcs' && '🧙'}
                {entry.category === 'quests' && '📜'}
                {entry.category === 'skills' && '✨'}
                {entry.category === 'maps' && '🗺️'}
              </span>
              <div>
                <div className="text-sm font-medium text-white">{entry.title}</div>
                <div className="text-xs text-muted-foreground capitalize">{entry.category}</div>
              </div>
            </Link>
          ))}
        </div>
      </div>
    </div>
  );
}

