'use client';

import { useState } from 'react';
import { useRouter } from 'next/navigation';
import { useForm } from 'react-hook-form';
import { zodResolver } from '@hookform/resolvers/zod';
import { z } from 'zod';
import { Button, Input, Textarea, Badge } from '@mmorpg/ui';

const guildCreateSchema = z.object({
  name: z
    .string()
    .min(3, 'Guild name must be at least 3 characters')
    .max(20, 'Guild name must be at most 20 characters')
    .regex(/^[a-zA-Z0-9_ ]+$/, 'Guild name can only contain letters, numbers, spaces, and underscores'),
  description: z
    .string()
    .max(500, 'Description must be at most 500 characters')
    .optional(),
  recruitmentOpen: z.boolean().default(true),
  recruitmentMessage: z
    .string()
    .max(200, 'Recruitment message must be at most 200 characters')
    .optional(),
});

type GuildCreateFormData = z.infer<typeof guildCreateSchema>;

// Mock player data to check requirements
const mockPlayerData = {
  level: 35,
  gold: 150000,
};

export default function GuildCreatePage() {
  const router = useRouter();
  const [isSubmitting, setIsSubmitting] = useState(false);
  const [serverError, setServerError] = useState<string | null>(null);

  const levelMet = mockPlayerData.level >= 30;
  const goldMet = mockPlayerData.gold >= 100000;
  const requirementsMet = levelMet && goldMet;

  const {
    register,
    handleSubmit,
    watch,
    formState: { errors },
  } = useForm<GuildCreateFormData>({
    resolver: zodResolver(guildCreateSchema),
    defaultValues: {
      recruitmentOpen: true,
    },
  });

  const descriptionValue = watch('description') || '';
  const nameValue = watch('name') || '';

  const onSubmit = async (data: GuildCreateFormData) => {
    if (!requirementsMet) return;

    setIsSubmitting(true);
    setServerError(null);

    try {
      // Mock API call
      await new Promise((resolve) => setTimeout(resolve, 1500));
      router.push('/guild/guild-1');
    } catch {
      setServerError('Failed to create guild. Please try again.');
    } finally {
      setIsSubmitting(false);
    }
  };

  return (
    <div className="mx-auto max-w-2xl space-y-8">
      {/* Page Header */}
      <div>
        <h1 className="font-heading text-2xl font-bold text-white">Create a Guild</h1>
        <p className="mt-1 text-sm text-muted-foreground">
          Establish your guild and recruit adventurers to your cause
        </p>
      </div>

      {/* Requirements Section */}
      <div className="rounded-2xl border-2 border-white/10 backdrop-blur-[16px] bg-[rgba(17,17,17,0.7)] p-6">
        <h2 className="font-heading text-sm font-semibold text-white mb-4">
          Creation Requirements
        </h2>
        <div className="grid grid-cols-1 sm:grid-cols-2 gap-4">
          <RequirementBadge
            label="Character Level"
            requirement="Level 30+"
            currentValue={`Level ${mockPlayerData.level}`}
            met={levelMet}
          />
          <RequirementBadge
            label="Gold Balance"
            requirement="100,000 Gold"
            currentValue={`${mockPlayerData.gold.toLocaleString()} Gold`}
            met={goldMet}
          />
        </div>
        {!requirementsMet && (
          <p className="mt-4 text-xs text-destructive">
            You must meet all requirements before creating a guild.
          </p>
        )}
      </div>

      {/* Creation Form */}
      <form onSubmit={handleSubmit(onSubmit)} className="space-y-6">
        {serverError && (
          <div className="rounded-xl border border-destructive/50 bg-destructive/10 px-4 py-3 text-sm text-destructive">
            {serverError}
          </div>
        )}

        {/* Guild Name */}
        <div className="rounded-2xl border-2 border-white/10 backdrop-blur-[16px] bg-[rgba(17,17,17,0.7)] p-6 space-y-4">
          <div className="space-y-2">
            <label htmlFor="guild-name" className="text-sm font-medium text-muted-foreground">
              Guild Name <span className="text-destructive">*</span>
            </label>
            <Input
              id="guild-name"
              type="text"
              placeholder="Enter guild name"
              error={!!errors.name}
              {...register('name')}
            />
            <div className="flex items-center justify-between">
              {errors.name ? (
                <p className="text-xs text-destructive">{errors.name.message}</p>
              ) : (
                <p className="text-xs text-muted-foreground">3-20 characters, letters, numbers, spaces, underscores</p>
              )}
              <span className={`text-xs ${nameValue.length > 20 ? 'text-destructive' : 'text-muted-foreground'}`}>
                {nameValue.length}/20
              </span>
            </div>
          </div>

          {/* Emblem Upload Placeholder */}
          <div className="space-y-2">
            <label className="text-sm font-medium text-muted-foreground">
              Guild Emblem
            </label>
