function AnnouncementCard({ announcement }: { announcement: GuildAnnouncement }) {
  const config = priorityConfig[announcement.priority];

  return (
    <div
      className={`rounded-xl border-2 ${config.borderColor} ${config.bgColor} p-4 transition-all duration-200 hover:bg-white/[0.03]`}
    >
      <div className="flex items-start justify-between gap-3">
        <div className="flex-1 min-w-0">
          <div className="flex flex-wrap items-center gap-2 mb-1.5">
            {announcement.isPinned && (
              <span className="flex items-center gap-1 text-[10px] font-semibold text-yellow-400 uppercase tracking-wider">
                <PinIcon className="h-3 w-3" />
                Pinned
              </span>
            )}
            <Badge
              variant="outline"
              className={`text-[10px] ${config.textColor} border-current/30`}
            >
              {config.icon} {config.label}
            </Badge>
          </div>
          <h3 className="text-sm font-semibold text-white truncate">
            {announcement.title}
          </h3>
          <p className="text-xs text-muted-foreground mt-1 line-clamp-2 leading-relaxed">
            {announcement.content}
          </p>
          <div className="flex items-center gap-3 mt-2.5 text-[11px] text-muted-foreground">
            <span>
              By <span className="text-white/80 font-medium">{announcement.author}</span>
            </span>
            <span className="h-1 w-1 rounded-full bg-white/20" />
            <span>{formatRelativeDate(announcement.createdAt)}</span>
          </div>
        </div>
      </div>
    </div>
  );
}

function formatRelativeDate(date: Date): string {
  const now = new Date();
  const diffMs = now.getTime() - date.getTime();
  const diffDays = Math.floor(diffMs / (1000 * 60 * 60 * 24));

  if (diffDays === 0) return 'Today';
  if (diffDays === 1) return 'Yesterday';
  if (diffDays < 7) return `${diffDays}d ago`;
  if (diffDays < 30) return `${Math.floor(diffDays / 7)}w ago`;
  return `${Math.floor(diffDays / 30)}mo ago`;
}

