export default function CreateListingPage() {
  const [selectedItem, setSelectedItem] = useState<InventoryItem | null>(null);
  const [listingType, setListingType] = useState<ListingType>('fixed');
  const [price, setPrice] = useState('');
  const [minBidIncrement, setMinBidIncrement] = useState('');
  const [duration, setDuration] = useState<ListingDuration>('48h');
  const [quantity, setQuantity] = useState('1');
  const [isSubmitting, setIsSubmitting] = useState(false);
  const [successMessage, setSuccessMessage] = useState('');
  const [errorMessage, setErrorMessage] = useState('');

  const handleSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    setErrorMessage('');
    setSuccessMessage('');

    if (!selectedItem) {
      setErrorMessage('Please select an item from your inventory.');
      return;
    }
    if (!price || parseInt(price) <= 0) {
      setErrorMessage('Please enter a valid price.');
      return;
    }
    if (listingType === 'auction' && (!minBidIncrement || parseInt(minBidIncrement) <= 0)) {
      setErrorMessage('Please enter a valid minimum bid increment for auctions.');
      return;
    }
    if (parseInt(quantity) > selectedItem.quantity) {
      setErrorMessage(`You only have ${selectedItem.quantity} of this item.`);
      return;
    }

    setIsSubmitting(true);
    // Simulate API call
    setTimeout(() => {
      setIsSubmitting(false);
      setSuccessMessage(`Successfully listed "${selectedItem.name}" for ${formatGold(parseInt(price))} gold!`);
      setSelectedItem(null);
      setPrice('');
      setMinBidIncrement('');
      setQuantity('1');
    }, 1500);
  };

  const fee = price ? Math.floor(parseInt(price) * 0.05) : 0;
  const youReceive = price ? parseInt(price) - fee : 0;

  return (
    <div className="max-w-4xl mx-auto space-y-6">
      {/* Page Header */}
      <div>
        <h1 className="font-heading text-2xl font-bold text-white">Create Listing</h1>
        <p className="mt-1 text-sm text-muted-foreground">
          List an item from your inventory on the marketplace
        </p>
      </div>

      {/* Success Message */}
      {successMessage && (
        <div className="rounded-2xl border-2 border-green-500/30 bg-green-500/10 p-4 flex items-center gap-3">
          <span className="text-green-400 text-lg">✅</span>
          <p className="text-sm text-green-300">{successMessage}</p>
        </div>
      )}

      {/* Error Message */}
      {errorMessage && (
        <div className="rounded-2xl border-2 border-red-500/30 bg-red-500/10 p-4 flex items-center gap-3">
          <span className="text-red-400 text-lg">❌</span>
          <p className="text-sm text-red-300">{errorMessage}</p>
        </div>
      )}

      <form onSubmit={handleSubmit} className="space-y-6">
        {/* Step 1: Select Item */}
        <div className="rounded-2xl border-2 border-white/10 backdrop-blur-[16px] bg-[rgba(17,17,17,0.7)] p-5">
          <h2 className="font-heading text-sm font-bold text-white mb-4 flex items-center gap-2">
            <span className="flex h-6 w-6 items-center justify-center rounded-full bg-primary/20 text-[10px] font-bold text-primary">1</span>
            Select Item from Inventory
          </h2>

          <div className="grid grid-cols-1 sm:grid-cols-2 gap-3 max-h-64 overflow-y-auto pr-2">
            {mockInventoryItems.map((item) => (
              <button
                key={item.id}
                type="button"
                onClick={() => {
                  setSelectedItem(item);
                  setQuantity('1');
                }}
                className={`flex items-center gap-3 rounded-xl border-2 p-3 text-left transition-all duration-200 ${
                  selectedItem?.id === item.id
                    ? `${rarityBorderColors[item.rarity]} bg-white/5`
                    : 'border-white/5 bg-[rgba(6,6,6,0.3)] hover:border-white/20 hover:bg-white/[0.02]'
                }`}
              >
                <div className={`flex h-10 w-10 flex-shrink-0 items-center justify-center rounded-lg border ${rarityBorderColors[item.rarity]} bg-[rgba(6,6,6,0.5)]`}>
                  <svg className={`h-5 w-5 ${rarityTextColors[item.rarity]}`} fill="none" viewBox="0 0 24 24" stroke="currentColor" strokeWidth={1.5}>
                    <path strokeLinecap="round" strokeLinejoin="round" d="M20.25 7.5l-.625 10.632a2.25 2.25 0 01-2.247 2.118H6.622a2.25 2.25 0 01-2.247-2.118L3.75 7.5m8.25 3v6.75m0 0l-3-3m3 3l3-3M3.375 7.5h17.25c.621 0 1.125-.504 1.125-1.125v-1.5c0-.621-.504-1.125-1.125-1.125H3.375c-.621 0-1.125.504-1.125 1.125v1.5c0 .621.504 1.125 1.125 1.125z" />
                  </svg>
                </div>
                <div className="flex-1 min-w-0">
                  <p className={`text-xs font-semibold truncate ${rarityTextColors[item.rarity]}`}>{item.name}</p>
                  <p className="text-[10px] text-muted-foreground">{item.category} • Qty: {item.quantity}</p>
                </div>
                {selectedItem?.id === item.id && (
                  <span className="text-primary text-sm">✓</span>
                )}
              </button>
            ))}
          </div>
        </div>

        {/* Step 2: Listing Type Toggle */}
        <div className="rounded-2xl border-2 border-white/10 backdrop-blur-[16px] bg-[rgba(17,17,17,0.7)] p-5">
          <h2 className="font-heading text-sm font-bold text-white mb-4 flex items-center gap-2">
            <span className="flex h-6 w-6 items-center justify-center rounded-full bg-primary/20 text-[10px] font-bold text-primary">2</span>
            Listing Type
          </h2>

          <div className="flex gap-3">
            <button
              type="button"
              onClick={() => setListingType('fixed')}
              className={`flex-1 rounded-xl border-2 p-4 text-center transition-all duration-200 ${
                listingType === 'fixed'
                  ? 'border-green-500/50 bg-green-500/10'
                  : 'border-white/10 bg-[rgba(6,6,6,0.3)] hover:border-white/20'
              }`}
            >
              <span className="text-2xl block mb-2">💰</span>
              <p className={`text-sm font-semibold ${listingType === 'fixed' ? 'text-green-400' : 'text-white'}`}>Fixed Price</p>
              <p className="text-[10px] text-muted-foreground mt-1">Set a buy-now price</p>
            </button>
            <button
              type="button"
              onClick={() => setListingType('auction')}
              className={`flex-1 rounded-xl border-2 p-4 text-center transition-all duration-200 ${
                listingType === 'auction'
                  ? 'border-yellow-500/50 bg-yellow-500/10'
                  : 'border-white/10 bg-[rgba(6,6,6,0.3)] hover:border-white/20'
              }`}
            >
              <span className="text-2xl block mb-2">🔨</span>
              <p className={`text-sm font-semibold ${listingType === 'auction' ? 'text-yellow-400' : 'text-white'}`}>Auction</p>
              <p className="text-[10px] text-muted-foreground mt-1">Let players bid</p>
            </button>
          </div>
        </div>

        {/* Step 3: Price & Duration */}
        <div className="rounded-2xl border-2 border-white/10 backdrop-blur-[16px] bg-[rgba(17,17,17,0.7)] p-5">
          <h2 className="font-heading text-sm font-bold text-white mb-4 flex items-center gap-2">
            <span className="flex h-6 w-6 items-center justify-center rounded-full bg-primary/20 text-[10px] font-bold text-primary">3</span>
            Price & Duration
          </h2>

          <div className="space-y-4">
            {/* Price */}
            <div>
              <label className="block text-[11px] uppercase tracking-wider text-muted-foreground mb-1.5">
                {listingType === 'fixed' ? 'Asking Price' : 'Starting Price'} (Gold)
              </label>
              <div className="relative">
                <span className="absolute left-3 top-1/2 -translate-y-1/2 text-yellow-400">🪙</span>
                <input
                  type="number"
                  placeholder="Enter price..."
                  value={price}
                  onChange={(e) => setPrice(e.target.value)}
                  min="1"
                  className="w-full rounded-xl border-2 border-white/10 bg-[rgba(6,6,6,0.5)] pl-10 pr-4 py-2.5 text-sm text-white placeholder:text-muted-foreground focus:border-primary/50 focus:outline-none focus:ring-1 focus:ring-primary/30"
                />
              </div>
            </div>

            {/* Min Bid Increment (Auction only) */}
            {listingType === 'auction' && (
              <div>
                <label className="block text-[11px] uppercase tracking-wider text-muted-foreground mb-1.5">
                  Minimum Bid Increment (Gold)
                </label>
                <div className="relative">
                  <span className="absolute left-3 top-1/2 -translate-y-1/2 text-yellow-400">🪙</span>
                  <input
                    type="number"
                    placeholder="Min bid increment..."
                    value={minBidIncrement}
                    onChange={(e) => setMinBidIncrement(e.target.value)}
                    min="1"
                    className="w-full rounded-xl border-2 border-white/10 bg-[rgba(6,6,6,0.5)] pl-10 pr-4 py-2.5 text-sm text-white placeholder:text-muted-foreground focus:border-primary/50 focus:outline-none focus:ring-1 focus:ring-primary/30"
                  />
                </div>
              </div>
            )}

            {/* Quantity */}
            {selectedItem && selectedItem.quantity > 1 && (
              <div>
                <label className="block text-[11px] uppercase tracking-wider text-muted-foreground mb-1.5">
                  Quantity (Max: {selectedItem.quantity})
                </label>
                <input
                  type="number"
                  value={quantity}
                  onChange={(e) => setQuantity(e.target.value)}
                  min="1"
                  max={selectedItem.quantity}
                  className="w-full rounded-xl border-2 border-white/10 bg-[rgba(6,6,6,0.5)] px-4 py-2.5 text-sm text-white focus:border-primary/50 focus:outline-none focus:ring-1 focus:ring-primary/30"
                />
              </div>
            )}

            {/* Duration */}
            <div>
              <label className="block text-[11px] uppercase tracking-wider text-muted-foreground mb-1.5">Duration</label>
              <div className="flex gap-2">
                {durations.map((d) => (
                  <button
                    key={d.value}
                    type="button"
                    onClick={() => setDuration(d.value)}
                    className={`flex-1 rounded-xl border-2 px-4 py-2.5 text-sm font-medium transition-all duration-200 ${
                      duration === d.value
                        ? 'border-primary/50 bg-primary/10 text-primary'
                        : 'border-white/10 bg-[rgba(6,6,6,0.3)] text-muted-foreground hover:text-white hover:border-white/20'
                    }`}
                  >
                    {d.label}
                  </button>
                ))}
              </div>
            </div>
          </div>
        </div>

        {/* Fee Summary */}
        {price && parseInt(price) > 0 && (
          <div className="rounded-2xl border-2 border-white/10 backdrop-blur-[16px] bg-[rgba(17,17,17,0.7)] p-5">
            <h3 className="text-xs font-semibold text-muted-foreground uppercase tracking-wider mb-3">Fee Summary</h3>
            <div className="space-y-2">
              <div className="flex justify-between text-sm">
                <span className="text-muted-foreground">Listing Price</span>
                <span className="text-white font-medium">{formatGold(parseInt(price))} gold</span>
              </div>
              <div className="flex justify-between text-sm">
                <span className="text-muted-foreground">Transaction Fee (5%)</span>
                <span className="text-red-400 font-medium">-{formatGold(fee)} gold</span>
              </div>
              <div className="border-t border-white/10 pt-2 flex justify-between text-sm">
                <span className="text-white font-semibold">You Receive</span>
                <span className="text-green-400 font-bold">{formatGold(youReceive)} gold</span>
              </div>
            </div>
          </div>
        )}

        {/* Submit Button */}
        <div className="flex gap-3">
          <Link
            href="/marketplace"
            className="rounded-xl border-2 border-white/10 bg-[rgba(17,17,17,0.7)] px-6 py-3 text-sm font-medium text-muted-foreground hover:text-white hover:border-white/20 transition-all duration-200"
          >
            Cancel
          </Link>
          <button
            type="submit"
            disabled={isSubmitting || !selectedItem || !price}
            className="flex-1 rounded-xl border-2 border-primary/50 bg-primary/20 px-6 py-3 text-sm font-bold text-primary hover:bg-primary/30 hover:shadow-[0_0_20px_#7c3aed30] disabled:opacity-40 disabled:cursor-not-allowed transition-all duration-200"
          >
            {isSubmitting ? (
              <span className="flex items-center justify-center gap-2">
                <svg className="animate-spin h-4 w-4" viewBox="0 0 24 24" fill="none">
                  <circle className="opacity-25" cx="12" cy="12" r="10" stroke="currentColor" strokeWidth="4" />
                  <path className="opacity-75" fill="currentColor" d="M4 12a8 8 0 018-8V0C5.373 0 0 5.373 0 12h4z" />
                </svg>
                Creating Listing...
              </span>
            ) : (
              `List ${listingType === 'auction' ? 'for Auction' : 'for Sale'}`
            )}
          </button>
        </div>
      </form>
    </div>
  );
}

'use client';

import { useState } from 'react';
import Link from 'next/link';
import { useParams } from 'next/navigation';

type ItemRarity = 'common' | 'uncommon' | 'rare' | 'epic' | 'legendary' | 'mythic';
type ListingType = 'fixed' | 'auction';

interface ListingDetail {
  id: string;
  itemName: string;
  itemCategory: string;
  itemRarity: ItemRarity;
  price: number;
  currentBid?: number;
  listingType: ListingType;
  sellerName: string;
  sellerLevel: number;
  sellerJoinDate: string;
  sellerTotalSales: number;
  levelRequirement: number;
  quantity: number;
  expiresAt: string;
  createdAt: string;
  totalBids?: number;
  minBidIncrement?: number;
  description?: string;
  stats: Record<string, number>;
}

const rarityBorderColors: Record<ItemRarity, string> = {
