  epic: 'shadow-[0_0_16px_rgba(192,132,252,0.25)]',
  legendary: 'shadow-[0_0_20px_rgba(251,146,60,0.3)]',
  mythic: 'shadow-[0_0_24px_rgba(248,113,113,0.35)]',
};

const rarityTextColors: Record<ItemRarity, string> = {
  common: 'text-gray-300',
  uncommon: 'text-green-400',
  rare: 'text-blue-400',
  epic: 'text-purple-400',
  legendary: 'text-orange-400',
  mythic: 'text-red-400',
};

const rarityBadgeColors: Record<ItemRarity, string> = {
  common: 'bg-gray-400/10 text-gray-300 border-gray-400/30',
  uncommon: 'bg-green-400/10 text-green-400 border-green-400/30',
  rare: 'bg-blue-400/10 text-blue-400 border-blue-400/30',
  epic: 'bg-purple-400/10 text-purple-400 border-purple-400/30',
  legendary: 'bg-orange-400/10 text-orange-400 border-orange-400/30',
  mythic: 'bg-red-400/10 text-red-400 border-red-400/30',
