// Default listing for unknown IDs
const defaultListing: ListingDetail = {
  id: 'ml-default', itemName: 'Dragon Scale Armor', itemCategory: 'Armor', itemRarity: 'epic',
  price: 2800000, listingType: 'fixed', sellerName: 'DragonSlayer', sellerLevel: 78,
