  expiresAt: new Date(Date.now() + 24 * 3600000).toISOString(),
  createdAt: new Date(Date.now() - 5 * 3600000).toISOString(),
  description: 'Armor crafted from the scales of an ancient dragon. Provides excellent protection against fire-based attacks.',
  stats: { defense: 380, hp: 500, fireResist: 45, durability: 100 },
};

function formatGold(amount: number): string {
  if (amount >= 1_000_000) return `${(amount / 1_000_000).toFixed(2)}M`;
  if (amount >= 1_000) return `${(amount / 1_000).toFixed(1)}K`;
  return amount.toLocaleString();
}

function getTimeRemaining(expiresAt: string): { text: string; urgent: boolean } {
  const now = new Date();
  const end = new Date(expiresAt);
  const diffMs = end.getTime() - now.getTime();
  if (diffMs <= 0) return { text: 'Expired', urgent: true };
  const hours = Math.floor(diffMs / 3600000);
  const minutes = Math.floor((diffMs % 3600000) / 60000);
  if (hours >= 24) return { text: `${Math.floor(hours / 24)}d ${hours % 24}h ${minutes}m`, urgent: false };
  if (hours > 0) return { text: `${hours}h ${minutes}m`, urgent: hours < 6 };
  return { text: `${minutes}m`, urgent: true };
}

function formatDate(dateStr: string): string {
  return new Date(dateStr).toLocaleDateString('en-US', { year: 'numeric', month: 'short', day: 'numeric' });
}

export default function MarketplaceItemDetailPage() {
  const params = useParams();
  const listingId = params.id as string;
  const listing = mockListingDetails[listingId] || defaultListing;

  const [bidAmount, setBidAmount] = useState('');
  const [showBuyConfirm, setShowBuyConfirm] = useState(false);
  const [showInsufficientFunds, setShowInsufficientFunds] = useState(false);
  const [purchaseSuccess, setPurchaseSuccess] = useState(false);

  const timeRemaining = getTimeRemaining(listing.expiresAt);

  // Mock user balance (intentionally low for some items to demonstrate insufficient funds)
  const userBalance = 3000000;

  const handleBuy = () => {
    if (listing.price > userBalance) {
      setShowInsufficientFunds(true);
      setShowBuyConfirm(false);
      return;
    }
    setShowBuyConfirm(false);
    setPurchaseSuccess(true);
  };

  const handleBid = () => {
    const amount = parseInt(bidAmount);
    if (!amount || amount <= 0) return;
    if (amount > userBalance) {
      setShowInsufficientFunds(true);
      return;
    }
    const minBid = (listing.currentBid || listing.price) + (listing.minBidIncrement || 1);
    if (amount < minBid) return;
    setPurchaseSuccess(true);
  };

  return (
    <div className="max-w-5xl mx-auto space-y-6">
      {/* Breadcrumb */}
      <nav className="flex items-center gap-2 text-sm text-muted-foreground">
        <Link href="/marketplace" className="hover:text-white transition-colors">Marketplace</Link>
        <span>/</span>
        <span className="text-white">{listing.itemName}</span>
      </nav>

      {/* Insufficient Funds Error */}
      {showInsufficientFunds && (
        <div className="rounded-2xl border-2 border-red-500/30 bg-red-500/10 p-5">
          <div className="flex items-start gap-3">
            <span className="text-red-400 text-xl mt-0.5">⚠️</span>
            <div>
              <h3 className="text-sm font-bold text-red-300">Insufficient Funds</h3>
              <p className="text-xs text-red-300/80 mt-1">
                You don&apos;t have enough gold to complete this purchase. Your balance is{' '}
                <span className="font-bold text-yellow-300">{formatGold(userBalance)}</span> gold,
                but this item costs{' '}
                <span className="font-bold text-white">{formatGold(listing.price)}</span> gold.
              </p>
              <p className="text-xs text-red-300/60 mt-2">
                You need <span className="font-semibold text-red-300">{formatGold(listing.price - userBalance)}</span> more gold.
              </p>
              <button
                onClick={() => setShowInsufficientFunds(false)}
                className="mt-3 rounded-lg border border-red-500/30 bg-red-500/10 px-3 py-1.5 text-[11px] font-medium text-red-300 hover:bg-red-500/20 transition-colors"
              >
                Dismiss
              </button>
            </div>
          </div>
        </div>
      )}

      {/* Purchase Success */}
      {purchaseSuccess && (
        <div className="rounded-2xl border-2 border-green-500/30 bg-green-500/10 p-5">
          <div className="flex items-center gap-3">
            <span className="text-green-400 text-xl">🎉</span>
            <div>
              <h3 className="text-sm font-bold text-green-300">
                {listing.listingType === 'auction' ? 'Bid Placed Successfully!' : 'Purchase Successful!'}
              </h3>
              <p className="text-xs text-green-300/80 mt-1">
                {listing.listingType === 'auction'
                  ? `Your bid of ${formatGold(parseInt(bidAmount))} gold has been placed.`
                  : `${listing.itemName} has been added to your inventory.`}
              </p>
            </div>
          </div>
        </div>
      )}

      <div className="grid grid-cols-1 lg:grid-cols-3 gap-6">
        {/* Left Column - Item Info */}
        <div className="lg:col-span-2 space-y-6">
          {/* Item Card */}
          <div className={`rounded-2xl border-2 ${rarityBorderColors[listing.itemRarity]} ${rarityGlowColors[listing.itemRarity]} backdrop-blur-[16px] bg-[rgba(17,17,17,0.7)] p-6`}>
            <div className="flex flex-col sm:flex-row gap-6">
              {/* Item Image */}
              <div className={`flex-shrink-0 w-full sm:w-40 aspect-square rounded-xl border-2 ${rarityBorderColors[listing.itemRarity]} bg-[rgba(6,6,6,0.5)] flex items-center justify-center`}>
                <svg
                  className={`h-20 w-20 opacity-40 ${rarityTextColors[listing.itemRarity]}`}
                  fill="none"
                  viewBox="0 0 24 24"
                  stroke="currentColor"
                  strokeWidth={1}
                >
                  <path strokeLinecap="round" strokeLinejoin="round" d="M20.25 7.5l-.625 10.632a2.25 2.25 0 01-2.247 2.118H6.622a2.25 2.25 0 01-2.247-2.118L3.75 7.5m8.25 3v6.75m0 0l-3-3m3 3l3-3M3.375 7.5h17.25c.621 0 1.125-.504 1.125-1.125v-1.5c0-.621-.504-1.125-1.125-1.125H3.375c-.621 0-1.125.504-1.125 1.125v1.5c0 .621.504 1.125 1.125 1.125z" />
                </svg>
              </div>

              {/* Item Details */}
              <div className="flex-1">
                <div className="flex items-start justify-between gap-3">
                  <div>
                    <h1 className={`font-heading text-xl font-bold ${rarityTextColors[listing.itemRarity]}`}>
                      {listing.itemName}
                    </h1>
                    <div className="flex items-center gap-2 mt-2">
                      <span className={`inline-block rounded-full border px-2.5 py-0.5 text-[10px] font-bold uppercase ${rarityBadgeColors[listing.itemRarity]}`}>
                        {listing.itemRarity}
                      </span>
                      <span className="text-xs text-muted-foreground">{listing.itemCategory}</span>
                      <span className="text-xs text-muted-foreground">•</span>
                      <span className="text-xs text-muted-foreground">Lv.{listing.levelRequirement}+</span>
                    </div>
                  </div>
                  {listing.listingType === 'auction' ? (
                    <span className="rounded-full bg-yellow-500/10 border border-yellow-500/30 px-2.5 py-1 text-[10px] font-bold text-yellow-400 uppercase">
                      Auction
                    </span>
                  ) : (
                    <span className="rounded-full bg-green-500/10 border border-green-500/30 px-2.5 py-1 text-[10px] font-bold text-green-400 uppercase">
                      Buy Now
                    </span>
                  )}
                </div>

                {listing.description && (
                  <p className="mt-3 text-sm text-muted-foreground leading-relaxed">
                    {listing.description}
                  </p>
                )}

                {/* Quantity */}
                {listing.quantity > 1 && (
                  <p className="mt-2 text-xs text-muted-foreground">
                    Quantity: <span className="text-white font-medium">x{listing.quantity}</span>
                  </p>
                )}
              </div>
            </div>
          </div>

          {/* Item Stats */}
          <div className="rounded-2xl border-2 border-white/10 backdrop-blur-[16px] bg-[rgba(17,17,17,0.7)] p-5">
            <h2 className="font-heading text-sm font-bold text-white mb-4 flex items-center gap-2">
