                    </div>
                  </div>
                  <div>
                    <p className="text-[10px] uppercase tracking-wider text-muted-foreground">Starting Price</p>
                    <p className="text-sm text-muted-foreground">{formatGold(listing.price)} gold</p>
                  </div>
