              <div className="flex items-center justify-between">
                <span className="text-[10px] uppercase tracking-wider text-muted-foreground">Your Balance</span>
                <div className="flex items-center gap-1">
                  <span className="text-yellow-400 text-xs">🪙</span>
                  <span className="text-sm font-semibold text-white">{formatGold(userBalance)}</span>
                </div>
              </div>
