          </svg>
          <p className="text-muted-foreground text-sm">
            {activeTab === 'active' && 'No active listings'}
            {activeTab === 'sold' && 'No sold items yet'}
            {activeTab === 'expired' && 'No expired listings'}
          </p>
          {activeTab === 'active' && (
            <Link
              href="/marketplace/create"
              className="mt-4 inline-flex items-center gap-2 rounded-xl border border-primary/30 bg-primary/10 px-4 py-2 text-xs font-medium text-primary hover:bg-primary/20 transition-colors"
            >
              Create your first listing
            </Link>
          )}
        </div>
      )}
    </div>
  );
}

import {
  Injectable,
  Inject,
  BadRequestException,
  NotFoundException,
  ForbiddenException,
} from '@nestjs/common';
import { PrismaClient } from '@mmorpg/database';
import { ListingType, ListingStatus } from '@mmorpg/types';
import { calculateTransactionFee, calculateSellerProceeds } from '@mmorpg/shared';
import Redis from 'ioredis';
import { REDIS_CLIENT } from './marketplace.module';
import { CreateListingInput } from './dto/create-listing.dto';
import { CreateAuctionInput } from './dto/create-auction.dto';
import { SearchQueryInput } from './dto/search-query.dto';

/** Maximum active listings per player */
const MAX_ACTIVE_LISTINGS = 50;

@Injectable()
export class MarketplaceService {
  constructor(
    @Inject(REDIS_CLIENT) private readonly redis: Redis,
    private readonly prisma: PrismaClient,
  ) {}

  /**
   * Create a fixed-price listing.
   * Validates the seller has fewer than 50 active listings.
   */
  async createListing(dto: CreateListingInput, sellerId: string) {
    await this.checkActiveListingLimit(sellerId);

    const expiresAt = new Date();
    expiresAt.setHours(expiresAt.getHours() + dto.duration);

    const listing = await this.prisma.marketplaceListing.create({
      data: {
        sellerId,
        itemId: dto.itemId,
        itemName: dto.itemName,
        itemCategory: dto.itemCategory,
        itemRarity: dto.itemRarity,
        quantity: dto.quantity,
        price: BigInt(dto.price),
        listingType: ListingType.FIXED_PRICE,
        expiresAt,
        status: ListingStatus.ACTIVE,
      },
    });

    return this.serializeListing(listing);
  }

  /**
   * Create an auction listing.
   * Validates the seller has fewer than 50 active listings.
   */
  async createAuction(dto: CreateAuctionInput, sellerId: string) {
    await this.checkActiveListingLimit(sellerId);

    const expiresAt = new Date();
    expiresAt.setHours(expiresAt.getHours() + dto.duration);

    const listing = await this.prisma.marketplaceListing.create({
      data: {
        sellerId,
        itemId: dto.itemId,
        itemName: dto.itemName,
        itemCategory: dto.itemCategory,
        itemRarity: dto.itemRarity,
        quantity: dto.quantity,
        price: BigInt(dto.startingPrice),
        listingType: ListingType.AUCTION,
        minBidIncrement: BigInt(dto.minBidIncrement),
        expiresAt,
        status: ListingStatus.ACTIVE,
      },
    });

    return this.serializeListing(listing);
  }

  /**
   * Purchase a fixed-price listing.
   * Atomic transaction: check buyer gold, deduct from buyer, add to seller (minus 5% fee),
   * transfer item, create Transaction record, mark listing as SOLD.
   */
  async purchaseItem(listingId: string, buyerId: string) {
    return this.prisma.$transaction(async (tx) => {
      const listing = await tx.marketplaceListing.findUnique({
        where: { id: listingId },
      });

      if (!listing) {
        throw new NotFoundException('Listing not found');
      }

      if (listing.status !== ListingStatus.ACTIVE) {
        throw new BadRequestException('Listing is no longer active');
      }

      if (listing.listingType !== ListingType.FIXED_PRICE) {
        throw new BadRequestException('Cannot directly purchase an auction listing. Use bid instead.');
      }

      if (listing.sellerId === buyerId) {
        throw new ForbiddenException('Cannot purchase your own listing');
      }

      if (listing.expiresAt < new Date()) {
        throw new BadRequestException('Listing has expired');
      }

      // Check buyer has sufficient gold
      const buyer = await tx.user.findUnique({
        where: { id: buyerId },
        select: { goldBalance: true },
      });

      if (!buyer) {
        throw new NotFoundException('Buyer not found');
      }

      if (buyer.goldBalance < listing.price) {
        throw new BadRequestException('Insufficient gold to complete purchase');
      }

      // Calculate fee and seller proceeds
      const fee = calculateTransactionFee(listing.price);
      const sellerProceeds = calculateSellerProceeds(listing.price);

      // Deduct gold from buyer
      await tx.user.update({
        where: { id: buyerId },
        data: { goldBalance: { decrement: listing.price } },
      });

      // Add gold to seller (minus fee)
      await tx.user.update({
        where: { id: listing.sellerId },
        data: { goldBalance: { increment: sellerProceeds } },
      });

      // Mark listing as sold
      await tx.marketplaceListing.update({
        where: { id: listingId },
        data: { status: ListingStatus.SOLD },
      });

      // Create transaction record
      const transaction = await tx.transaction.create({
        data: {
          listingId,
          buyerId,
          sellerId: listing.sellerId,
          itemName: listing.itemName,
          quantity: listing.quantity,
          totalPrice: listing.price,
          fee,
        },
      });

      return {
        id: transaction.id,
        listingId: transaction.listingId,
        buyerId: transaction.buyerId,
        sellerId: transaction.sellerId,
        itemName: transaction.itemName,
        quantity: transaction.quantity,
        totalPrice: transaction.totalPrice.toString(),
        fee: transaction.fee.toString(),
        createdAt: transaction.createdAt.toISOString(),
      };
    });
  }

  /**
   * Place a bid on an auction listing.
   * Bid must be >= current highest bid + minBidIncrement.
   * Returns previous bidder's gold if outbid.
   */
  async placeBid(listingId: string, amount: string, bidderId: string) {
    const bidAmount = BigInt(amount);

    return this.prisma.$transaction(async (tx) => {
      const listing = await tx.marketplaceListing.findUnique({
        where: { id: listingId },
        include: {
          bids: {
            orderBy: { amount: 'desc' },
            take: 1,
          },
        },
      });

      if (!listing) {
        throw new NotFoundException('Listing not found');
      }

      if (listing.status !== ListingStatus.ACTIVE) {
        throw new BadRequestException('Listing is no longer active');
      }

      if (listing.listingType !== ListingType.AUCTION) {
        throw new BadRequestException('This listing is not an auction');
      }

      if (listing.sellerId === bidderId) {
        throw new ForbiddenException('Cannot bid on your own auction');
      }

      if (listing.expiresAt < new Date()) {
        throw new BadRequestException('Auction has expired');
      }

      // Determine minimum bid
      const highestBid = listing.bids[0];
      const minBidIncrement = listing.minBidIncrement ?? BigInt(1);
      let minimumBid: bigint;

      if (highestBid) {
        minimumBid = highestBid.amount + minBidIncrement;
      } else {
        // First bid must be at least the starting price
        minimumBid = listing.price;
      }

      if (bidAmount < minimumBid) {
        throw new BadRequestException(
          `Bid must be at least ${minimumBid.toString()}. Current highest bid: ${highestBid ? highestBid.amount.toString() : '0'}, min increment: ${minBidIncrement.toString()}`,
        );
      }

      // Check bidder has sufficient gold
      const bidder = await tx.user.findUnique({
        where: { id: bidderId },
        select: { goldBalance: true },
      });

      if (!bidder) {
        throw new NotFoundException('Bidder not found');
      }

      if (bidder.goldBalance < bidAmount) {
        throw new BadRequestException('Insufficient gold to place bid');
      }

      // Return previous bidder's gold (if any)
      if (highestBid) {
        await tx.user.update({
          where: { id: highestBid.bidderId },
          data: { goldBalance: { increment: highestBid.amount } },
        });
      }

      // Deduct gold from new bidder
      await tx.user.update({
        where: { id: bidderId },
        data: { goldBalance: { decrement: bidAmount } },
      });

      // Create bid record
      const bid = await tx.auctionBid.create({
        data: {
          listingId,
          bidderId,
          amount: bidAmount,
        },
      });

      return {
        id: bid.id,
        listingId: bid.listingId,
        bidderId: bid.bidderId,
        amount: bid.amount.toString(),
        createdAt: bid.createdAt.toISOString(),
      };
    });
  }

  /**
   * Search marketplace listings with filters.
   * Supports: category, rarity, price range, text search on itemName, sorting, pagination.
   */
  async searchListings(query: SearchQueryInput) {
    const where: Record<string, unknown> = {
      status: ListingStatus.ACTIVE,
      deletedAt: null,
      expiresAt: { gt: new Date() },
    };

    if (query.query) {
      where.itemName = { contains: query.query, mode: 'insensitive' };
    }

    if (query.category) {
      where.itemCategory = query.category;
    }

    if (query.rarity) {
      where.itemRarity = query.rarity;
    }

    if (query.listingType) {
      where.listingType = query.listingType;
    }

    if (query.minPrice || query.maxPrice) {
      const priceFilter: Record<string, bigint> = {};
      if (query.minPrice) priceFilter.gte = BigInt(query.minPrice);
      if (query.maxPrice) priceFilter.lte = BigInt(query.maxPrice);
      where.price = priceFilter;
    }

    // Determine sort order
    let orderBy: Record<string, string> = { createdAt: 'desc' };
    switch (query.sortBy) {
      case 'price_asc':
        orderBy = { price: 'asc' };
        break;
      case 'price_desc':
        orderBy = { price: 'desc' };
        break;
      case 'newest':
        orderBy = { createdAt: 'desc' };
        break;
      case 'ending_soon':
        orderBy = { expiresAt: 'asc' };
        break;
    }

    const skip = (query.page - 1) * query.pageSize;

    const [listings, total] = await Promise.all([
      this.prisma.marketplaceListing.findMany({
        where: where as any,
        orderBy,
        skip,
        take: query.pageSize,
        include: {
          bids: {
            orderBy: { amount: 'desc' },
            take: 1,
          },
          _count: { select: { bids: true } },
        },
      }),
      this.prisma.marketplaceListing.count({ where: where as any }),
    ]);

    const totalPages = Math.ceil(total / query.pageSize);

    return {
      items: listings.map((listing) => ({
        id: listing.id,
        sellerId: listing.sellerId,
        itemId: listing.itemId,
        itemName: listing.itemName,
        itemCategory: listing.itemCategory,
        itemRarity: listing.itemRarity,
        quantity: listing.quantity,
        price: listing.price.toString(),
        listingType: listing.listingType,
        minBidIncrement: listing.minBidIncrement?.toString() ?? null,
        currentBid: listing.bids[0]?.amount.toString() ?? null,
        bidCount: listing._count.bids,
        expiresAt: listing.expiresAt.toISOString(),
        status: listing.status,
        createdAt: listing.createdAt.toISOString(),
      })),
      total,
      page: query.page,
      pageSize: query.pageSize,
      totalPages,
      hasNextPage: query.page < totalPages,
      hasPreviousPage: query.page > 1,
    };
  }

  /**
   * Get price history for an item over a given period (7d, 30d, 90d).
   * Aggregates completed transactions by day.
   */
  async getPriceHistory(itemId: string, period: '7d' | '30d' | '90d') {
    const now = new Date();
    const startDate = new Date();

    switch (period) {
      case '7d':
        startDate.setDate(now.getDate() - 7);
        break;
      case '30d':
        startDate.setDate(now.getDate() - 30);
        break;
      case '90d':
        startDate.setDate(now.getDate() - 90);
        break;
    }

    // Get all transactions for this item within the period
    const transactions = await this.prisma.transaction.findMany({
      where: {
        listing: {
          itemId,
        },
        createdAt: {
          gte: startDate,
          lte: now,
        },
      },
      orderBy: { createdAt: 'asc' },
      select: {
        totalPrice: true,
        quantity: true,
        createdAt: true,
      },
    });

    // Group by date and compute aggregates
    const dailyData = new Map<string, { total: bigint; min: bigint; max: bigint; volume: number }>();

    for (const tx of transactions) {
      const dateKey = tx.createdAt.toISOString().split('T')[0];
      const unitPrice = tx.totalPrice / BigInt(tx.quantity);

      const existing = dailyData.get(dateKey);
      if (existing) {
        existing.total += unitPrice;
        existing.volume += 1;
        if (unitPrice < existing.min) existing.min = unitPrice;
        if (unitPrice > existing.max) existing.max = unitPrice;
      } else {
        dailyData.set(dateKey, {
          total: unitPrice,
          min: unitPrice,
          max: unitPrice,
          volume: 1,
        });
      }
    }

    const priceHistory = Array.from(dailyData.entries()).map(([date, data]) => ({
      date,
      averagePrice: (data.total / BigInt(data.volume)).toString(),
      minPrice: data.min.toString(),
      maxPrice: data.max.toString(),
      volume: data.volume,
    }));

    return priceHistory;
  }

  /**
   * Process expired listings.
   * Returns items to seller, sets status to EXPIRED, creates notification.
   * For auctions with bids, completes the sale to the highest bidder.
   */
  async processExpiredListings() {
    const now = new Date();

    const expiredListings = await this.prisma.marketplaceListing.findMany({
      where: {
        status: ListingStatus.ACTIVE,
        expiresAt: { lte: now },
        deletedAt: null,
      },
      include: {
        bids: {
          orderBy: { amount: 'desc' },
          take: 1,
        },
      },
    });

    const results = { expired: 0, soldViaAuction: 0 };

    for (const listing of expiredListings) {
      if (listing.listingType === ListingType.AUCTION && listing.bids.length > 0) {
        // Auction with bids: complete the sale to highest bidder
        await this.completeAuction(listing, listing.bids[0]);
        results.soldViaAuction++;
      } else {
        // Fixed-price or auction with no bids: expire the listing
        await this.expireListing(listing);
        results.expired++;
      }
    }

    return results;
  }

  /**
   * Complete an auction sale to the highest bidder.
   */
  private async completeAuction(
    listing: { id: string; sellerId: string; itemName: string; quantity: number },
    highestBid: { bidderId: string; amount: bigint },
  ) {
    await this.prisma.$transaction(async (tx) => {
      const fee = calculateTransactionFee(highestBid.amount);
      const sellerProceeds = calculateSellerProceeds(highestBid.amount);

      // Add gold to seller (minus fee) - bidder's gold was already deducted when bid was placed
      await tx.user.update({
        where: { id: listing.sellerId },
        data: { goldBalance: { increment: sellerProceeds } },
      });

      // Mark listing as sold
      await tx.marketplaceListing.update({
        where: { id: listing.id },
        data: { status: ListingStatus.SOLD },
      });

      // Create transaction record
      await tx.transaction.create({
        data: {
          listingId: listing.id,
          buyerId: highestBid.bidderId,
          sellerId: listing.sellerId,
          itemName: listing.itemName,
          quantity: listing.quantity,
          totalPrice: highestBid.amount,
          fee,
        },
      });

      // Notify seller
      await tx.notification.create({
        data: {
          userId: listing.sellerId,
          type: 'MARKETPLACE',
          title: 'Auction Completed',
          message: `Your auction for ${listing.itemName} has been sold for ${highestBid.amount.toString()} gold.`,
          data: { listingId: listing.id, buyerId: highestBid.bidderId },
        },
      });

      // Notify buyer
      await tx.notification.create({
        data: {
          userId: highestBid.bidderId,
          type: 'MARKETPLACE',
          title: 'Auction Won',
          message: `You won the auction for ${listing.itemName} for ${highestBid.amount.toString()} gold.`,
          data: { listingId: listing.id },
        },
      });
    });
  }

  /**
   * Expire a listing: set status to EXPIRED and notify the seller.
   * For auctions with no bids, also return any held gold (none in this case).
   */
  private async expireListing(listing: { id: string; sellerId: string; itemName: string }) {
    await this.prisma.$transaction(async (tx) => {
      // Mark listing as expired
      await tx.marketplaceListing.update({
        where: { id: listing.id },
        data: { status: ListingStatus.EXPIRED },
      });

      // Notify seller that listing expired and item is returned
      await tx.notification.create({
        data: {
          userId: listing.sellerId,
          type: 'MARKETPLACE',
          title: 'Listing Expired',
          message: `Your listing for ${listing.itemName} has expired. The item has been returned to your inventory.`,
          data: { listingId: listing.id },
        },
      });
    });
  }

  /**
   * Check that a seller has not exceeded the maximum active listings limit.
   */
  private async checkActiveListingLimit(sellerId: string) {
    const activeCount = await this.prisma.marketplaceListing.count({
      where: {
        sellerId,
        status: ListingStatus.ACTIVE,
        deletedAt: null,
      },
    });

    if (activeCount >= MAX_ACTIVE_LISTINGS) {
      throw new BadRequestException(
        `Maximum active listings limit reached (${MAX_ACTIVE_LISTINGS}). Please wait for existing listings to expire or cancel them.`,
      );
    }
  }

  /**
   * Serialize a listing for API response (convert BigInt to string).
   */
  private serializeListing(listing: any) {
    return {
      id: listing.id,
      sellerId: listing.sellerId,
      itemId: listing.itemId,
      itemName: listing.itemName,
      itemCategory: listing.itemCategory,
      itemRarity: listing.itemRarity,
      quantity: listing.quantity,
      price: listing.price.toString(),
      listingType: listing.listingType,
      minBidIncrement: listing.minBidIncrement?.toString() ?? null,
      expiresAt: listing.expiresAt.toISOString(),
      status: listing.status,
      createdAt: listing.createdAt.toISOString(),
    };
  }
}

import {
  Controller,
  Post,
  Get,
  Param,
  Body,
  Query,
  UseGuards,
  Req,
  UsePipes,
  BadRequestException,
} from '@nestjs/common';
import { MarketplaceService } from './marketplace.service';
import { JwtAuthGuard } from '../auth/guards/jwt-auth.guard';
import { ZodValidationPipe } from '../../common/pipes/zod-validation.pipe';
import { CreateListingSchema, CreateListingInput } from './dto/create-listing.dto';
import { CreateAuctionSchema, CreateAuctionInput } from './dto/create-auction.dto';
import { SearchQuerySchema, SearchQueryInput } from './dto/search-query.dto';

@Controller('api/marketplace')
export class MarketplaceController {
  constructor(private readonly marketplaceService: MarketplaceService) {}

  /**
   * POST /api/marketplace/listings
   * Create a fixed-price listing. Requires authentication.
   */
  @Post('listings')
  @UseGuards(JwtAuthGuard)
  @UsePipes(new ZodValidationPipe(CreateListingSchema))
  async createListing(
    @Body() dto: CreateListingInput,
    @Req() req: { user: { userId: string } },
  ) {
    const listing = await this.marketplaceService.createListing(dto, req.user.userId);
    return {
      success: true,
      data: listing,
      timestamp: new Date().toISOString(),
    };
  }

  /**
   * POST /api/marketplace/auctions
   * Create an auction listing. Requires authentication.
   */
  @Post('auctions')
  @UseGuards(JwtAuthGuard)
  @UsePipes(new ZodValidationPipe(CreateAuctionSchema))
  async createAuction(
    @Body() dto: CreateAuctionInput,
    @Req() req: { user: { userId: string } },
  ) {
    const listing = await this.marketplaceService.createAuction(dto, req.user.userId);
    return {
      success: true,
      data: listing,
      timestamp: new Date().toISOString(),
    };
  }

  /**
   * POST /api/marketplace/:id/buy
   * Purchase a fixed-price listing. Requires authentication.
   */
  @Post(':id/buy')
  @UseGuards(JwtAuthGuard)
  async purchaseItem(
    @Param('id') listingId: string,
    @Req() req: { user: { userId: string } },
  ) {
    const transaction = await this.marketplaceService.purchaseItem(listingId, req.user.userId);
    return {
      success: true,
      data: transaction,
      timestamp: new Date().toISOString(),
    };
  }

  /**
   * POST /api/marketplace/:id/bid
   * Place a bid on an auction listing. Requires authentication.
   */
  @Post(':id/bid')
  @UseGuards(JwtAuthGuard)
  async placeBid(
    @Param('id') listingId: string,
    @Body() body: { amount?: string },
    @Req() req: { user: { userId: string } },
  ) {
    if (!body.amount || !/^\d+$/.test(body.amount)) {
      throw new BadRequestException('amount is required and must be a positive integer string');
    }

    if (BigInt(body.amount) <= BigInt(0)) {
      throw new BadRequestException('amount must be greater than 0');
    }

    const bid = await this.marketplaceService.placeBid(listingId, body.amount, req.user.userId);
    return {
      success: true,
      data: bid,
      timestamp: new Date().toISOString(),
    };
  }

  /**
   * GET /api/marketplace/search
   * Search marketplace listings with filters. Public endpoint.
   */
  @Get('search')
  async searchListings(@Query() rawQuery: Record<string, unknown>) {
    const parsed = SearchQuerySchema.safeParse(rawQuery);
    if (!parsed.success) {
      throw new BadRequestException({
        statusCode: 400,
        error: 'ValidationError',
        message: 'Invalid search parameters',
        details: parsed.error.issues.map((issue) => ({
          field: issue.path.join('.'),
          message: issue.message,
        })),
      });
    }

    const results = await this.marketplaceService.searchListings(parsed.data);
    return {
      success: true,
      data: results,
      timestamp: new Date().toISOString(),
    };
  }

  /**
   * GET /api/marketplace/items/:itemId/price-history
   * Get price history for an item. Public endpoint.
   */
  @Get('items/:itemId/price-history')
  async getPriceHistory(
    @Param('itemId') itemId: string,
    @Query('period') period?: string,
  ) {
    const validPeriods = ['7d', '30d', '90d'] as const;
    const selectedPeriod = validPeriods.includes(period as any)
      ? (period as '7d' | '30d' | '90d')
      : '7d';

    const history = await this.marketplaceService.getPriceHistory(itemId, selectedPeriod);
    return {
      success: true,
      data: {
        itemId,
        period: selectedPeriod,
        priceHistory: history,
      },
      timestamp: new Date().toISOString(),
    };
  }

  /**
   * POST /api/marketplace/expiry-job
   * Trigger the listing expiry job manually (admin/cron use).
   * In production this would be triggered by a scheduled job.
   */
  @Post('expiry-job')
  @UseGuards(JwtAuthGuard)
  async processExpiredListings() {
    const results = await this.marketplaceService.processExpiredListings();
    return {
      success: true,
      data: results,
      timestamp: new Date().toISOString(),
    };
  }
}

import { Module } from '@nestjs/common';
import { ConfigModule, ConfigService } from '@nestjs/config';
import { PrismaClient } from '@mmorpg/database';
import Redis from 'ioredis';
import { MarketplaceService } from './marketplace.service';
import { MarketplaceController } from './marketplace.controller';

export const REDIS_CLIENT = 'MARKETPLACE_REDIS_CLIENT';

@Module({
  imports: [ConfigModule],
  controllers: [MarketplaceController],
  providers: [
    MarketplaceService,
    {
      provide: PrismaClient,
      useFactory: () => new PrismaClient(),
    },
    {
      provide: REDIS_CLIENT,
      useFactory: (configService: ConfigService) => {
        const host = configService.get<string>('REDIS_HOST', 'localhost');
        const port = configService.get<number>('REDIS_PORT', 6379);
        const password = configService.get<string>('REDIS_PASSWORD', '');

        return new Redis({
          host,
          port,
          password: password || undefined,
          maxRetriesPerRequest: 3,
          retryStrategy: (times: number) => Math.min(times * 50, 2000),
        });
      },
      inject: [ConfigService],
    },
  ],
  exports: [MarketplaceService],
})
export class MarketplaceModule {}

import { describe, it, expect, vi, beforeEach } from 'vitest';
import { MarketplaceService } from './marketplace.service';
import { ListingType, ListingStatus, ItemCategory, ItemRarity } from '@mmorpg/types';

// Mock PrismaClient
function createMockPrisma() {
  return {
    marketplaceListing: {
      create: vi.fn(),
      findUnique: vi.fn(),
      findMany: vi.fn(),
      count: vi.fn(),
      update: vi.fn(),
    },
    user: {
      findUnique: vi.fn(),
      update: vi.fn(),
    },
    transaction: {
      create: vi.fn(),
      findMany: vi.fn(),
    },
    auctionBid: {
      create: vi.fn(),
    },
    notification: {
      create: vi.fn(),
    },
    $transaction: vi.fn(),
  };
}

// Mock Redis
function createMockRedis() {
  return {
    get: vi.fn().mockResolvedValue(null),
    set: vi.fn().mockResolvedValue('OK'),
    del: vi.fn().mockResolvedValue(1),
    keys: vi.fn().mockResolvedValue([]),
  };
}

describe('MarketplaceService', () => {
  let service: MarketplaceService;
  let prisma: ReturnType<typeof createMockPrisma>;
  let redis: ReturnType<typeof createMockRedis>;

  beforeEach(() => {
    prisma = createMockPrisma();
    redis = createMockRedis();
    service = new MarketplaceService(redis as any, prisma as any);
  });

