    it('should create a fixed-price listing successfully', async () => {
      prisma.marketplaceListing.count.mockResolvedValue(5);
      prisma.marketplaceListing.create.mockResolvedValue({
        id: 'listing-1',
        sellerId: 'seller-1',
        itemId: 'item-1',
        itemName: 'Iron Sword',
        itemCategory: ItemCategory.WEAPON,
        itemRarity: ItemRarity.COMMON,
        quantity: 1,
        price: BigInt(10000),
        listingType: ListingType.FIXED_PRICE,
        minBidIncrement: null,
        expiresAt: new Date('2025-01-02T00:00:00Z'),
        status: ListingStatus.ACTIVE,
        createdAt: new Date('2025-01-01T00:00:00Z'),
      });

      const result = await service.createListing(
        {
          itemId: 'item-1',
          itemName: 'Iron Sword',
          itemCategory: ItemCategory.WEAPON,
          itemRarity: ItemRarity.COMMON,
          quantity: 1,
          price: '10000',
          duration: 24,
        },
        'seller-1',
      );

      expect(result.id).toBe('listing-1');
      expect(result.price).toBe('10000');
      expect(result.listingType).toBe(ListingType.FIXED_PRICE);
      expect(prisma.marketplaceListing.create).toHaveBeenCalledWith(
        expect.objectContaining({
          data: expect.objectContaining({
            sellerId: 'seller-1',
            listingType: ListingType.FIXED_PRICE,
            price: BigInt(10000),
          }),
        }),
      );
    });

    it('should reject listing when seller has 50 active listings', async () => {
      prisma.marketplaceListing.count.mockResolvedValue(50);

      await expect(
        service.createListing(
          {
            itemId: 'item-1',
            itemName: 'Iron Sword',
