  describe('createAuction', () => {
    it('should create an auction listing successfully', async () => {
      prisma.marketplaceListing.count.mockResolvedValue(0);
      prisma.marketplaceListing.create.mockResolvedValue({
        id: 'auction-1',
        sellerId: 'seller-1',
        itemId: 'item-2',
        itemName: 'Dragon Staff',
        itemCategory: ItemCategory.WEAPON,
        itemRarity: ItemRarity.EPIC,
