import { useEffect, useRef, useCallback, useState } from 'react';
import { useRealtimeStore } from '@/stores/realtime.store';

export type MarketplaceEventType = 'new_listing' | 'sale' | 'auction_bid' | 'auction_end';

export interface MarketplaceEvent {
  id: string;
  type: MarketplaceEventType;
  itemId: string;
  itemName: string;
  price: number;
  playerName: string;
  timestamp: string;
  auctionId?: string;
  currentBid?: number;
}

interface UseMarketplaceRealtimeOptions {
  onEvent?: (event: MarketplaceEvent) => void;
  onError?: (error: Error) => void;
  autoConnect?: boolean;
}

/**
 * Hook for connecting to marketplace realtime updates via WebSocket
 * Handles connection management, reconnection with exponential backoff, and event subscription
 */
export function useMarketplaceRealtime(options: UseMarketplaceRealtimeOptions = {}) {
  const { onEvent, onError, autoConnect = true } = options;
  const { connectionStatus, setConnectionStatus } = useRealtimeStore();
  
  const wsRef = useRef<WebSocket | null>(null);
  const reconnectTimeoutRef = useRef<NodeJS.Timeout | null>(null);
  const reconnectAttemptsRef = useRef(0);
  const [isSubscribed, setIsSubscribed] = useState(false);

  const MAX_RECONNECT_ATTEMPTS = 5;
  const BASE_RECONNECT_DELAY = 1000; // 1 second

  const calculateBackoffDelay = useCallback((attempt: number): number => {
    // Exponential backoff: baseDelay * 2^attempt
    return BASE_RECONNECT_DELAY * Math.pow(2, attempt);
  }, []);

  const connect = useCallback(() => {
    if (wsRef.current?.readyState === WebSocket.OPEN) {
      return; // Already connected
    }

    try {
      setConnectionStatus('connecting');
      const wsUrl = process.env.NEXT_PUBLIC_WS_URL || 'ws://localhost:3002';
      const ws = new WebSocket(`${wsUrl}/marketplace`);
      wsRef.current = ws;

      ws.onopen = () => {
        setConnectionStatus('connected');
        reconnectAttemptsRef.current = 0;
        setIsSubscribed(true);
      };

      ws.onmessage = (event) => {
        try {
          const data = JSON.parse(event.data) as MarketplaceEvent;
          onEvent?.(data);
        } catch (error) {
          const err = error instanceof Error ? error : new Error('Failed to parse message');
          onError?.(err);
        }
      };

      ws.onclose = () => {
        setConnectionStatus('disconnected');
        setIsSubscribed(false);

        // Attempt reconnection with exponential backoff
        if (reconnectAttemptsRef.current < MAX_RECONNECT_ATTEMPTS) {
          const delay = calculateBackoffDelay(reconnectAttemptsRef.current);
          reconnectAttemptsRef.current += 1;
          setConnectionStatus('reconnecting');
          reconnectTimeoutRef.current = setTimeout(connect, delay);
        }
      };

      ws.onerror = (error) => {
        const err = new Error(`WebSocket error: ${error}`);
        onError?.(err);
        ws.close();
      };
    } catch (error) {
      const err = error instanceof Error ? error : new Error('Failed to connect to WebSocket');
      onError?.(err);
      setConnectionStatus('disconnected');
    }
  }, [setConnectionStatus, onEvent, onError, calculateBackoffDelay]);

  const disconnect = useCallback(() => {
    if (wsRef.current) {
      wsRef.current.close();
      wsRef.current = null;
    }
    if (reconnectTimeoutRef.current) {
      clearTimeout(reconnectTimeoutRef.current);
    }
    setConnectionStatus('disconnected');
    setIsSubscribed(false);
  }, [setConnectionStatus]);

  const subscribe = useCallback((eventTypes: MarketplaceEventType[]) => {
    if (wsRef.current?.readyState === WebSocket.OPEN) {
      wsRef.current.send(
        JSON.stringify({
          action: 'subscribe',
          events: eventTypes,
        })
      );
    }
  }, []);

  const unsubscribe = useCallback((eventTypes: MarketplaceEventType[]) => {
    if (wsRef.current?.readyState === WebSocket.OPEN) {
      wsRef.current.send(
        JSON.stringify({
          action: 'unsubscribe',
          events: eventTypes,
        })
      );
    }
  }, []);

  useEffect(() => {
    if (autoConnect) {
      connect();
    }

    return () => {
      disconnect();
    };
  }, [autoConnect, connect, disconnect]);

  return {
    isConnected: connectionStatus === 'connected',
    isSubscribed,
    connectionStatus,
    subscribe,
    unsubscribe,
    disconnect,
    reconnect: connect,
  };
}

'use client';

import * as React from 'react';
import { useState, useEffect } from 'react';

export interface CountdownTime {
  days: number;
  hours: number;
  minutes: number;
  seconds: number;
  isExpired: boolean;
  totalSeconds: number;
}

interface CountdownTimerProps {
  endTime: string | Date;
  onExpire?: () => void;
  showDays?: boolean;
  compact?: boolean;
}

function calculateTimeLeft(endTime: string | Date): CountdownTime {
  const end = typeof endTime === 'string' ? new Date(endTime) : endTime;
  const now = new Date();
  const diff = end.getTime() - now.getTime();

  if (diff <= 0) {
    return {
      days: 0,
      hours: 0,
      minutes: 0,
      seconds: 0,
      isExpired: true,
      totalSeconds: 0,
    };
  }

  const totalSeconds = Math.floor(diff / 1000);
  const days = Math.floor(totalSeconds / (24 * 60 * 60));
  const hours = Math.floor((totalSeconds % (24 * 60 * 60)) / (60 * 60));
  const minutes = Math.floor((totalSeconds % (60 * 60)) / 60);
  const seconds = totalSeconds % 60;

  return {
    days,
    hours,
    minutes,
    seconds,
    isExpired: false,
    totalSeconds,
  };
}

/**
 * Countdown timer component for auctions and listings
 * Displays time remaining with automatic updates
 */
export function CountdownTimer({
  endTime,
  onExpire,
  showDays = true,
  compact = false,
}: CountdownTimerProps) {
  const [timeLeft, setTimeLeft] = useState<CountdownTime>(() =>
    calculateTimeLeft(endTime)
  );

  useEffect(() => {
    const timer = setInterval(() => {
      const newTimeLeft = calculateTimeLeft(endTime);
      setTimeLeft(newTimeLeft);

      if (newTimeLeft.isExpired && onExpire) {
        onExpire();
      }
    }, 1000);

    return () => clearInterval(timer);
  }, [endTime, onExpire]);

  if (timeLeft.isExpired) {
    return (
      <div className="text-center">
        <p className="text-sm font-bold text-red-400">Auction Ended</p>
      </div>
    );
  }

  if (compact) {
    // Compact format: "2d 5h 30m"
    const parts = [];
    if (showDays && timeLeft.days > 0) parts.push(`${timeLeft.days}d`);
    if (timeLeft.hours > 0) parts.push(`${timeLeft.hours}h`);
    if (timeLeft.minutes > 0) parts.push(`${timeLeft.minutes}m`);
    if (parts.length === 0) parts.push(`${timeLeft.seconds}s`);

    return (
      <span className="font-mono text-sm font-semibold text-white">
        {parts.join(' ')}
      </span>
    );
  }

  // Full format with visual display
  const isUrgent = timeLeft.totalSeconds < 1800; // Less than 30 minutes
  const isCritical = timeLeft.totalSeconds < 300; // Less than 5 minutes

  return (
    <div className="space-y-2">
      <div className="flex items-center justify-center gap-2">
        {[
          { value: timeLeft.days, label: 'DAYS', show: showDays && timeLeft.days > 0 },
          { value: timeLeft.hours, label: 'HRS', show: true },
          { value: timeLeft.minutes, label: 'MIN', show: true },
          { value: timeLeft.seconds, label: 'SEC', show: true },
        ]
          .filter((unit) => unit.show)
          .map((unit, index, arr) => (
            <React.Fragment key={unit.label}>
              {index > 0 && (
                <span className="text-2xl font-bold text-muted-foreground">:</span>
              )}
              <div className="flex flex-col items-center">
                <span
                  className={`font-heading text-3xl font-bold tabular-nums ${
                    isCritical
                      ? 'text-red-400 animate-pulse'
                      : isUrgent
                        ? 'text-orange-400'
                        : 'text-white'
                  }`}
                >
                  {String(unit.value).padStart(2, '0')}
                </span>
                <span className="text-[9px] text-muted-foreground uppercase tracking-wider">
                  {unit.label}
                </span>
              </div>
            </React.Fragment>
          ))}
      </div>

      {/* Status indicator */}
      {isUrgent && (
        <div className="flex items-center justify-center gap-1.5">
          <span className="h-2 w-2 rounded-full bg-orange-400 animate-pulse" />
          <span className="text-[10px] text-orange-400 font-medium">
            {isCritical ? 'Ending very soon!' : 'Ending soon'}
          </span>
        </div>
      )}
    </div>
  );
}

/**
 * Hook for managing countdown state
 */
export function useCountdown(endTime: string | Date) {
  const [timeLeft, setTimeLeft] = useState<CountdownTime>(() =>
    calculateTimeLeft(endTime)
  );

  useEffect(() => {
    const timer = setInterval(() => {
      setTimeLeft(calculateTimeLeft(endTime));
    }, 1000);

    return () => clearInterval(timer);
  }, [endTime]);

  return timeLeft;
}

