  itemImage: null,
  description:
    'A legendary blade forged in the heart of the Frozen Abyss. Deals bonus ice damage and has a chance to freeze enemies.',
  stats: {
    attack: 1450,
    speed: 120,
    iceDamage: 350,
    freezeChance: '15%',
  },
  seller: {
    name: 'DragonSlayer99',
    level: 92,
  },
  startingPrice: 2_000_000,
  currentBid: 5_750_000,
  minBidIncrement: 100_000,
  totalBids: 14,
  endsAt: new Date(Date.now() + 3 * 60 * 60 * 1000 + 42 * 60 * 1000).toISOString(),
  createdAt: new Date(Date.now() - 20 * 60 * 60 * 1000).toISOString(),
  watchers: 47,
};

const mockBidHistory: BidEntry[] = [
  { id: 'bid-1', bidderName: 'PhoenixRise', amount: 5_750_000, timestamp: new Date(Date.now() - 5 * 60000).toISOString(), isHighest: true },
  { id: 'bid-2', bidderName: 'ArcaneStorm', amount: 5_500_000, timestamp: new Date(Date.now() - 18 * 60000).toISOString() },
  { id: 'bid-3', bidderName: 'PhoenixRise', amount: 5_200_000, timestamp: new Date(Date.now() - 45 * 60000).toISOString() },
  { id: 'bid-4', bidderName: 'NightWhisper', amount: 4_800_000, timestamp: new Date(Date.now() - 90 * 60000).toISOString() },
  { id: 'bid-5', bidderName: 'IronFortress', amount: 4_500_000, timestamp: new Date(Date.now() - 120 * 60000).toISOString() },
  { id: 'bid-6', bidderName: 'ArcaneStorm', amount: 4_000_000, timestamp: new Date(Date.now() - 180 * 60000).toISOString() },
  { id: 'bid-7', bidderName: 'CrystalGuard', amount: 3_500_000, timestamp: new Date(Date.now() - 300 * 60000).toISOString() },
  { id: 'bid-8', bidderName: 'StarFire', amount: 3_000_000, timestamp: new Date(Date.now() - 420 * 60000).toISOString() },
  { id: 'bid-9', bidderName: 'WindRunner', amount: 2_500_000, timestamp: new Date(Date.now() - 600 * 60000).toISOString() },
  { id: 'bid-10', bidderName: 'HolyLight', amount: 2_200_000, timestamp: new Date(Date.now() - 720 * 60000).toISOString() },
];

const rarityColors: Record<string, { border: string; text: string; glow: string }> = {
  common: { border: 'border-gray-400/30', text: 'text-gray-300', glow: '' },
  uncommon: { border: 'border-green-400/30', text: 'text-green-400', glow: 'shadow-[0_0_12px_rgba(74,222,128,0.15)]' },
  rare: { border: 'border-blue-400/30', text: 'text-blue-400', glow: 'shadow-[0_0_12px_rgba(96,165,250,0.15)]' },
  epic: { border: 'border-purple-400/30', text: 'text-purple-400', glow: 'shadow-[0_0_12px_rgba(192,132,252,0.15)]' },
  legendary: { border: 'border-orange-400/30', text: 'text-orange-400', glow: 'shadow-[0_0_16px_rgba(251,146,60,0.2)]' },
  mythic: { border: 'border-red-400/30', text: 'text-red-400', glow: 'shadow-[0_0_16px_rgba(248,113,113,0.2)]' },
};

function formatGold(amount: number): string {
  if (amount >= 1_000_000) {
    return `${(amount / 1_000_000).toFixed(2)}M`;
  }
  if (amount >= 1_000) {
    return `${(amount / 1_000).toFixed(1)}K`;
  }
  return amount.toLocaleString();
}

export default function AuctionPage() {
  const params = useParams();
  const auction = mockAuction;
  const rarity = rarityColors[auction.itemRarity];

  const [bidAmount, setBidAmount] = useState<string>('');
  const [bids, setBids] = useState<BidEntry[]>(mockBidHistory);
  const [currentBid, setCurrentBid] = useState(auction.currentBid);
  const [isSubmitting, setIsSubmitting] = useState(false);
  const [notification, setNotification] = useState<{ type: 'success' | 'error' | 'outbid'; message: string } | null>(null);
  const [lastRefresh, setLastRefresh] = useState(Date.now());
  const [auctionEnded, setAuctionEnded] = useState(false);

  const minimumBid = currentBid + auction.minBidIncrement;

  // Connect to realtime marketplace updates for this auction
  const { isConnected } = useMarketplaceRealtime({
    autoConnect: true,
    onEvent: (event: MarketplaceEvent) => {
      // Only process events for this auction
      if (event.auctionId === auction.id && event.type === 'auction_bid') {
        const newBid: BidEntry = {
          id: event.id,
          bidderName: event.playerName,
          amount: event.currentBid || event.price,
          timestamp: event.timestamp,
          isHighest: true,
        };
        setBids((prev) => [newBid, ...prev.map((b) => ({ ...b, isHighest: false }))]);
        setCurrentBid(event.currentBid || event.price);
        setLastRefresh(Date.now());

        // Show outbid notification if current user was outbid
        if (bids[0]?.bidderName === 'You') {
          setNotification({
            type: 'outbid',
            message: 'You have been outbid! Place a higher bid to stay in the lead.',
          });
        }
      }
    },
    onError: (error) => {
      console.warn('Realtime auction error:', error);
    },
  });

  // Clear notification after 5 seconds
  useEffect(() => {
    if (notification) {
      const timer = setTimeout(() => setNotification(null), 5000);
      return () => clearTimeout(timer);
    }
  }, [notification]);

  const handlePlaceBid = useCallback(async () => {
    const amount = parseInt(bidAmount.replace(/,/g, ''), 10);
    if (isNaN(amount) || amount < minimumBid) {
      setNotification({ type: 'error', message: `Minimum bid is ${formatGold(minimumBid)} gold.` });
      return;
    }

    setIsSubmitting(true);
    // Simulate API call
    await new Promise((resolve) => setTimeout(resolve, 1000));

    const newBid: BidEntry = {
      id: `bid-${Date.now()}`,
      bidderName: 'You',
      amount,
      timestamp: new Date().toISOString(),
      isHighest: true,
    };

    setBids((prev) => [newBid, ...prev.map((b) => ({ ...b, isHighest: false }))]);
    setCurrentBid(amount);
    setBidAmount('');
    setIsSubmitting(false);
    setNotification({ type: 'success', message: 'Bid placed successfully! You are now the highest bidder.' });
  }, [bidAmount, minimumBid, bids]);

  const handleAuctionEnd = useCallback(() => {
    setAuctionEnded(true);
  }, []);

  return (
    <div className="space-y-6">
      {/* Breadcrumb */}
      <nav className="flex items-center gap-2 text-sm text-muted-foreground">
        <Link href="/marketplace" className="hover:text-white transition-colors">
          Marketplace
        </Link>
        <span>/</span>
        <span className="text-white">Auction</span>
      </nav>

      {/* Notification Banner */}
      {notification && (
        <div
          className={`rounded-xl border-2 p-4 flex items-center gap-3 transition-all duration-300 animate-in slide-in-from-top-2 ${
            notification.type === 'outbid'
              ? 'border-orange-500/50 bg-orange-500/10'
              : notification.type === 'error'
                ? 'border-red-500/50 bg-red-500/10'
                : 'border-green-500/50 bg-green-500/10'
          }`}
        >
          <span className="text-lg">
            {notification.type === 'outbid' ? '⚠️' : notification.type === 'error' ? '❌' : '✅'}
          </span>
          <p
            className={`text-sm font-medium ${
              notification.type === 'outbid'
                ? 'text-orange-300'
                : notification.type === 'error'
                  ? 'text-red-300'
                  : 'text-green-300'
            }`}
          >
            {notification.message}
          </p>
          <button
            onClick={() => setNotification(null)}
            className="ml-auto text-muted-foreground hover:text-white transition-colors"
            type="button"
          >
            ✕
          </button>
        </div>
      )}

      <div className="grid grid-cols-1 lg:grid-cols-3 gap-6">
        {/* Left Column - Item Details */}
        <div className="lg:col-span-2 space-y-6">
          {/* Item Card */}
          <div className={`rounded-2xl border-2 ${rarity.border} backdrop-blur-[16px] bg-[rgba(17,17,17,0.7)] p-6 ${rarity.glow}`}>
            <div className="flex flex-col sm:flex-row gap-5">
              {/* Item Image Placeholder */}
              <div className={`h-32 w-32 flex-shrink-0 rounded-2xl border-2 ${rarity.border} bg-[rgba(6,6,6,0.5)] flex items-center justify-center`}>
                <span className="text-4xl">⚔️</span>
              </div>

              <div className="flex-1">
                <div className="flex items-center gap-2 mb-1">
                  <span className={`text-[10px] uppercase tracking-wider font-bold ${rarity.text}`}>
                    {auction.itemRarity}
                  </span>
                  <span className="text-[10px] text-muted-foreground">•</span>
                  <span className="text-[10px] text-muted-foreground">{auction.itemCategory}</span>
                </div>
                <h1 className={`font-heading text-xl font-bold ${rarity.text}`}>
                  {auction.itemName}
                </h1>
                <p className="text-sm text-muted-foreground mt-2">{auction.description}</p>

                {/* Item Stats */}
                <div className="flex flex-wrap gap-2 mt-3">
                  {Object.entries(auction.stats).map(([key, value]) => (
                    <span
                      key={key}
                      className="rounded-lg border border-white/10 bg-white/[0.03] px-2.5 py-1 text-[11px] text-white"
                    >
                      <span className="text-muted-foreground capitalize">{key.replace(/([A-Z])/g, ' $1').trim()}:</span>{' '}
                      <span className="font-semibold">{value}</span>
                    </span>
                  ))}
                </div>

                {/* Seller Info */}
                <div className="flex items-center gap-2 mt-4">
                  <span className="text-[10px] text-muted-foreground">Seller:</span>
                  <span className="text-sm font-medium text-white">{auction.seller.name}</span>
                  <span className="rounded-full bg-primary/20 border border-primary/30 px-2 py-0.5 text-[9px] font-bold text-primary">
                    Lv.{auction.seller.level}
                  </span>
                </div>
              </div>
            </div>
          </div>

          {/* Bid History */}
          <BidHistory bids={bids} maxDisplay={10} />
        </div>

        {/* Right Column - Bidding Panel */}
        <div className="space-y-5">
          {/* Countdown Timer */}
          <div className="rounded-2xl border-2 border-red-500/30 backdrop-blur-[16px] bg-[rgba(17,17,17,0.7)] p-5">
            <div className="flex items-center gap-2 mb-3">
              <svg className="h-4 w-4 text-red-400" fill="none" viewBox="0 0 24 24" stroke="currentColor" strokeWidth={2}>
                <path strokeLinecap="round" strokeLinejoin="round" d="M12 8v4l3 3m6-3a9 9 0 11-18 0 9 9 0 0118 0z" />
              </svg>
              <span className="text-[10px] uppercase tracking-wider text-red-400 font-semibold">
                {auctionEnded ? 'Auction Ended' : 'Time Remaining'}
              </span>
            </div>
            <CountdownTimer
              endTime={auction.endsAt}
              onExpire={handleAuctionEnd}
              showDays={false}
              compact={false}
            />
          </div>

          {/* Current Bid Display */}
          <div className="rounded-2xl border-2 border-primary/30 backdrop-blur-[16px] bg-[rgba(17,17,17,0.7)] p-5">
            <div className="flex items-center justify-between mb-2">
              <span className="text-[10px] uppercase tracking-wider text-muted-foreground">Current Bid</span>
              <span className="text-[10px] text-muted-foreground">{bids.length} bids</span>
            </div>
            <div className="flex items-center gap-2">
              <span className="text-yellow-400 text-xl">🪙</span>
              <span className="font-heading text-2xl font-bold text-yellow-300">
                {formatGold(currentBid)}
              </span>
            </div>
            <div className="flex items-center gap-2 mt-2">
              <span className="text-[10px] text-muted-foreground">Highest bidder:</span>
              <span className="text-sm font-medium text-white">{bids[0]?.bidderName ?? 'None'}</span>
            </div>
            <div className="mt-3 pt-3 border-t border-white/5">
              <div className="flex items-center justify-between text-[11px]">
                <span className="text-muted-foreground">Starting price</span>
                <span className="text-white">{formatGold(auction.startingPrice)}</span>
              </div>
              <div className="flex items-center justify-between text-[11px] mt-1">
                <span className="text-muted-foreground">Min increment</span>
                <span className="text-white">{formatGold(auction.minBidIncrement)}</span>
              </div>
              <div className="flex items-center justify-between text-[11px] mt-1">
                <span className="text-muted-foreground">Watchers</span>
                <span className="text-white">{auction.watchers}</span>
              </div>
            </div>
          </div>

          {/* Place Bid Form */}
          <div className="rounded-2xl border-2 border-secondary/30 backdrop-blur-[16px] bg-[rgba(17,17,17,0.7)] p-5">
            <h3 className="font-heading text-sm font-bold text-white mb-3">Place a Bid</h3>
            <div className="space-y-3">
              <div>
                <label className="text-[10px] uppercase tracking-wider text-muted-foreground mb-1 block">
                  Your Bid (min: {formatGold(minimumBid)})
                </label>
                <div className="relative">
                  <span className="absolute left-3 top-1/2 -translate-y-1/2 text-yellow-400 text-sm">🪙</span>
                  <input
                    type="text"
                    value={bidAmount}
                    onChange={(e) => {
                      const val = e.target.value.replace(/[^0-9,]/g, '');
                      setBidAmount(val);
                    }}
                    placeholder={minimumBid.toLocaleString()}
                    className="w-full rounded-xl border-2 border-white/10 bg-[rgba(6,6,6,0.5)] pl-9 pr-4 py-3 text-sm text-white placeholder:text-muted-foreground focus:border-secondary/50 focus:outline-none focus:ring-1 focus:ring-secondary/30 transition-all"
                    disabled={auctionEnded || isSubmitting}
                  />
                </div>
                {bidAmount && parseInt(bidAmount.replace(/,/g, ''), 10) < minimumBid && (
                  <p className="text-[10px] text-red-400 mt-1">
                    Bid must be at least {formatGold(minimumBid)} gold
                  </p>
                )}
              </div>

              {/* Quick bid buttons */}
              <div className="flex gap-2">
                {[minimumBid, minimumBid + auction.minBidIncrement, minimumBid + auction.minBidIncrement * 5].map(
                  (amount) => (
                    <button
                      key={amount}
                      onClick={() => setBidAmount(amount.toString())}
                      className="flex-1 rounded-lg border border-white/10 bg-white/[0.03] py-1.5 text-[10px] text-muted-foreground hover:text-white hover:bg-white/5 transition-all"
                      type="button"
                      disabled={auctionEnded}
                    >
                      {formatGold(amount)}
                    </button>
                  )
                )}
              </div>

              <button
                onClick={handlePlaceBid}
                disabled={auctionEnded || isSubmitting || !bidAmount}
                className="w-full rounded-xl border-2 border-secondary/50 bg-secondary/20 py-3 text-sm font-bold text-secondary hover:bg-secondary/30 hover:shadow-[0_0_20px_rgba(6,182,212,0.2)] disabled:opacity-50 disabled:cursor-not-allowed transition-all duration-200"
                type="button"
              >
                {isSubmitting ? (
                  <span className="flex items-center justify-center gap-2">
                    <svg className="animate-spin h-4 w-4" viewBox="0 0 24 24">
                      <circle className="opacity-25" cx="12" cy="12" r="10" stroke="currentColor" strokeWidth="4" fill="none" />
                      <path className="opacity-75" fill="currentColor" d="M4 12a8 8 0 018-8V0C5.373 0 0 5.373 0 12h4z" />
                    </svg>
                    Placing Bid...
                  </span>
                ) : auctionEnded ? (
                  'Auction Ended'
                ) : (
                  '🔨 Place Bid'
                )}
              </button>
            </div>

            {/* Auto-refresh indicator */}
            <div className="flex items-center gap-1.5 mt-3 pt-3 border-t border-white/5">
              <span className={`h-1.5 w-1.5 rounded-full ${isConnected ? 'bg-green-400 animate-pulse' : 'bg-yellow-400'}`} />
              <span className="text-[9px] text-muted-foreground">
                {isConnected ? 'Live updates' : 'Demo mode'} • Last updated {Math.floor((Date.now() - lastRefresh) / 1000)}s ago
              </span>
            </div>
          </div>

          {/* Price History Link */}
          <Link
            href={`/marketplace/${params.id}/price-history`}
            className="block rounded-2xl border-2 border-white/10 backdrop-blur-[16px] bg-[rgba(17,17,17,0.7)] p-4 hover:border-primary/30 hover:bg-[rgba(17,17,17,0.9)] transition-all duration-200 group"
          >
            <div className="flex items-center gap-3">
              <svg className="h-5 w-5 text-primary group-hover:text-primary/80 transition-colors" fill="none" viewBox="0 0 24 24" stroke="currentColor" strokeWidth={2}>
                <path strokeLinecap="round" strokeLinejoin="round" d="M7 12l3-3 3 3 4-4M8 21l4-4 4 4M3 4h18M4 4h16v12a1 1 0 01-1 1H5a1 1 0 01-1-1V4z" />
              </svg>
              <div>
                <p className="text-sm font-medium text-white">View Price History</p>
                <p className="text-[10px] text-muted-foreground">7d / 30d / 90d price trends</p>
              </div>
              <svg className="h-4 w-4 text-muted-foreground ml-auto group-hover:translate-x-0.5 transition-transform" fill="none" viewBox="0 0 24 24" stroke="currentColor" strokeWidth={2}>
                <path strokeLinecap="round" strokeLinejoin="round" d="M9 5l7 7-7 7" />
              </svg>
            </div>
          </Link>
        </div>
      </div>
    </div>
  );
}

